import React, { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Bus, User, Phone, Mail, FileText, MapPin } from 'lucide-react'
import { useAuth } from '../customhooks/AuthContext'
import axiosInstance from '../utils/axiosInstance'

const RegisterOperator = () => {
  const navigate = useNavigate()
  const { user, updateUser } = useAuth()
  const [formData, setFormData] = useState({
    agencyName: '',
    contactPerson: '',
    businessPhone: '',
    businessEmail: '',
    gstNumber: '',
    city: '',
    state: ''
  })
  const [image, setImage] = useState(null)
  const [message, setMessage] = useState('')
  const [loading, setLoading] = useState(false)

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value })
  }

  const handleImageChange = (e) => {
    setImage(e.target.files[0])
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setLoading(true)
    setMessage('')
    try {
      const data = new FormData()
      Object.keys(formData).forEach(key => {
        data.append(key, formData[key])
      })
      if (image) {
        data.append('image', image)
      }

      const res = await axiosInstance.post('/operator/add', data, {
        headers: { 
          'Content-Type': 'multipart/form-data'
        }
      })
      
      setMessage(res.data.message)
      
      if (user) {
        const updatedUser = { ...user, role: 'bus_admin' }
        updateUser(updatedUser)
      }

      setTimeout(() => {
        navigate('/operator-dashboard')
      }, 2000)

    } catch (error) {
      setMessage(error.response?.data?.message || 'Something went wrong')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '40px 20px', background: 'var(--bg-body)' }}>
      <div className="panel card-animated" style={{ maxWidth: '600px', width: '100%', padding: '40px' }}>
        <div style={{ textAlign: 'center', marginBottom: '30px' }}>
          <div style={{ width: '60px', height: '60px', borderRadius: '50%', background: 'rgba(99,102,241,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 16px' }}>
            <Bus size={30} style={{ color: '#6366f1' }} />
          </div>
          <h2 style={{ fontSize: '24px', fontWeight: 'bold', color: 'var(--text-heading)', marginBottom: '8px' }}>Register Bus Agency</h2>
          <p style={{ color: 'var(--text-muted)' }}>Partner with JourneyHub to manage and sell bus tickets</p>
        </div>

        {message && (
          <div style={{ padding: '12px', borderRadius: '8px', marginBottom: '20px', background: message.includes('success') ? 'rgba(52,211,153,0.1)' : 'rgba(248,113,113,0.1)', color: message.includes('success') ? '#34d399' : '#f87171', textAlign: 'center' }}>
            {message}
          </div>
        )}

        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
          
          <div className="input-wrapper">
            <Bus className="input-icon" />
            <input type="text" className="input-field" placeholder="Travels/Agency Name *" name="agencyName" value={formData.agencyName} onChange={handleChange} required />
          </div>

          <div style={{ display: 'flex', gap: '20px' }}>
            <div className="input-wrapper" style={{ flex: 1 }}>
              <User className="input-icon" />
              <input type="text" className="input-field" placeholder="Contact Person *" name="contactPerson" value={formData.contactPerson} onChange={handleChange} required />
            </div>
            <div className="input-wrapper" style={{ flex: 1 }}>
              <Phone className="input-icon" />
              <input type="text" className="input-field" placeholder="Business Phone *" name="businessPhone" value={formData.businessPhone} onChange={handleChange} required />
            </div>
          </div>

          <div className="input-wrapper">
            <Mail className="input-icon" />
            <input type="email" className="input-field" placeholder="Business Email *" name="businessEmail" value={formData.businessEmail} onChange={handleChange} required />
          </div>

          <div className="input-wrapper">
            <FileText className="input-icon" />
            <input type="text" className="input-field" placeholder="GST Number (Optional)" name="gstNumber" value={formData.gstNumber} onChange={handleChange} />
          </div>

          <div style={{ display: 'flex', gap: '20px' }}>
            <div className="input-wrapper" style={{ flex: 1 }}>
              <MapPin className="input-icon" />
              <input type="text" className="input-field" placeholder="Head Office City" name="city" value={formData.city} onChange={handleChange} />
            </div>
            <div className="input-wrapper" style={{ flex: 1 }}>
              <MapPin className="input-icon" />
              <input type="text" className="input-field" placeholder="Head Office State" name="state" value={formData.state} onChange={handleChange} />
            </div>
          </div>

          <div className="input-wrapper">
            <FileText className="input-icon" />
            <input type="file" className="input-field" accept="image/*" onChange={handleImageChange} style={{ paddingTop: '10px' }} />
          </div>

          <button type="submit" className="btn-primary" style={{ marginTop: '10px' }} disabled={loading}>
            {loading ? 'Submitting Application...' : 'Register Agency'}
          </button>

        </form>
      </div>
    </div>
  )
}

export default RegisterOperator

import { useEffect, useState } from 'react'
import { X } from 'lucide-react'
import { useAuth } from '../customhooks/AuthContext'
import axiosInstance from '../utils/axiosInstance'

const BOOKING_API = '/booking'

const AddBooking = ({ onCreated, initialType = 'hotel', initialId = '', initialCity = '', isModal = false, onClose }) => {
  const [bookingType, setBookingType] = useState(initialType)
  const [selectedId, setSelectedId] = useState(initialId)
  const [journeyDate, setJourneyDate] = useState('')
  const [totalSeats, setTotalSeats] = useState(1)
  const [specialRequest, setSpecialRequest] = useState('')
  const [hotels, setHotels] = useState([])
  const [buses, setBuses] = useState([])
  const [message, setMessage] = useState('')
  const [loading, setLoading] = useState(false)
  const [selectedFromCity, setSelectedFromCity] = useState('')
  const [selectedToCity, setSelectedToCity] = useState(initialCity || '')
  const { token } = useAuth()

  useEffect(() => {
    if (initialType) setBookingType(initialType)
    if (initialId !== undefined) setSelectedId(initialId)
    if (initialCity) setSelectedToCity(initialCity)
  }, [initialType, initialId, initialCity])

  useEffect(() => {
    let ignore = false

    Promise.all([
      axiosInstance.get('/hotel/gethotel'),
      axiosInstance.get('/bus/get'),
    ])
      .then(([hotelRes, busRes]) => {
        if (ignore) return

        const approvedHotels = (hotelRes.data.hotels || []).filter(
          (hotel) => hotel.approvalStatus?.status && hotel.availableRooms > 0,
        )

        setHotels(approvedHotels)
        setBuses((busRes.data.buses || []).filter((bus) => bus.availableSeats > 0))
      })
      .catch((error) => {
        if (!ignore) {
          setMessage(error.response?.data?.message || 'Could not load hotels and buses')
        }
      })

    return () => {
      ignore = true
    }
  }, [])

  const filteredHotels = selectedToCity 
    ? hotels.filter(h => h.location?.city === selectedToCity) 
    : hotels

  const filteredBuses = buses.filter(b => {
    if (selectedFromCity && b.fromCityID?.city !== selectedFromCity) return false
    if (selectedToCity && b.toCityID?.city !== selectedToCity) return false
    return true
  })

  const uniqueFromCities = Array.from(new Set(buses.filter(b => !selectedToCity || b.toCityID?.city === selectedToCity).map(b => b.fromCityID?.city).filter(Boolean)))
  const uniqueToCities = Array.from(new Set([...buses.map(b => b.toCityID?.city), ...hotels.map(h => h.location?.city)].filter(Boolean)))

  const options = bookingType === 'hotel' ? filteredHotels : filteredBuses
  const selectedItem = options.find((item) => item._id === selectedId)
  const price = bookingType === 'hotel' ? selectedItem?.pricePerNight : selectedItem?.fare
  const totalAmount = Number(price || 0) * Number(totalSeats || 0)

  const changeType = (e) => {
    setBookingType(e.target.value)
    setSelectedId('')
    setTotalSeats(1)
    setMessage('')
    setSelectedFromCity('')
    if (!initialCity) setSelectedToCity('')
  }

  const createBooking = async (e) => {
    e.preventDefault()

    if (!token) {
      setMessage('Please login first')
      return
    }

    try {
      setLoading(true)
      setMessage('')

      const bookingData = {
        bookingType,
        journeyDate,
        totalSeats: Number(totalSeats),
        specialRequest: specialRequest.trim(),
      }

      if (bookingType === 'hotel') {
        bookingData.hotel = selectedId
      } else {
        bookingData.bus = selectedId
      }

      const res = await axiosInstance.post(`${BOOKING_API}/addbooking`, bookingData)

      setMessage(res.data.message)
      setSelectedId('')
      setJourneyDate('')
      setTotalSeats(1)
      setSpecialRequest('')

      if (onCreated) {
        setTimeout(() => {
          onCreated(res.data.booking)
        }, 1500)
      }
    } catch (error) {
      setMessage(error.response?.data?.message || 'Booking failed')
    } finally {
      setLoading(false)
    }
  }

  const minimumDate = new Date().toISOString().split('T')[0]

  return (
    <form className={isModal ? "modal-box" : "panel"} onSubmit={createBooking} style={isModal ? { maxWidth: '600px', padding: '28px 32px' } : {}}>
      <div className="panel-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div className="panel-title-group">
          <span className="panel-eyebrow">New Booking</span>
          <h2 className="panel-title">Book Your Trip</h2>
          <p className="panel-desc">Choose a hotel or bus and confirm your booking.</p>
        </div>
        {isModal && onClose && (
          <button
            type="button"
            className="modal-close"
            onClick={onClose}
            aria-label="Close modal"
          >
            <X size={18} />
          </button>
        )}
      </div>

      <div className="d-form cols-2">
        <div className="d-field">
          <label className="d-label">Booking Type</label>
          {initialId ? (
            <input className="d-input" value={bookingType === 'hotel' ? 'Hotel' : 'Bus'} disabled style={{ opacity: 0.7, cursor: 'not-allowed' }} />
          ) : (
            <select className="d-select" name="bookingType" value={bookingType} onChange={changeType}>
              <option value="hotel">Hotel</option>
              <option value="bus">Bus</option>
            </select>
          )}
        </div>

        <div className="d-field">
          <label className="d-label">Destination (To City)</label>
          {initialCity ? (
            <input className="d-input" value={initialCity} disabled style={{ opacity: 0.7, cursor: 'not-allowed' }} />
          ) : (
            <select className="d-select" value={selectedToCity} onChange={(e) => { setSelectedToCity(e.target.value); setSelectedId(''); }}>
              <option value="">All Cities</option>
              {uniqueToCities.map(city => (
                <option value={city} key={city}>{city}</option>
              ))}
            </select>
          )}
        </div>

        {bookingType === 'bus' && (
          <div className="d-field">
            <label className="d-label">Origin (From City)</label>
            {initialId ? (
              <input className="d-input" value={selectedItem ? selectedItem.fromCityID?.city || 'Unknown' : 'Loading...'} disabled style={{ opacity: 0.7, cursor: 'not-allowed' }} />
            ) : (
              <select className="d-select" value={selectedFromCity} onChange={(e) => { setSelectedFromCity(e.target.value); setSelectedId(''); }}>
                <option value="">Any</option>
                {uniqueFromCities.map(city => (
                  <option value={city} key={city}>{city}</option>
                ))}
              </select>
            )}
          </div>
        )}



        <div className="d-field">
          <label className="d-label">{bookingType === 'hotel' ? 'Select Hotel' : 'Select Bus'}</label>
          {initialId ? (
            <input className="d-input" value={selectedItem ? (bookingType === 'hotel' ? selectedItem.hotelName : `${selectedItem.busName} (${selectedItem.busNumber})`) : 'Selected'} disabled style={{ opacity: 0.7, cursor: 'not-allowed' }} />
          ) : (
            <select
              className="d-select"
              name={bookingType === 'hotel' ? 'hotel' : 'bus'}
              value={selectedId}
              onChange={(e) => setSelectedId(e.target.value)}
              required
            >
              <option value="">Select one</option>
              {options.map((item) => (
                <option value={item._id} key={item._id}>
                  {bookingType === 'hotel'
                    ? `${item.hotelName} - Rs. ${item.pricePerNight} (${item.availableRooms} rooms left)`
                    : `${item.busName} (${item.busNumber}) - ${item.fromCityID?.city || 'Unknown'} to ${item.toCityID?.city || 'Unknown'} - Rs. ${item.fare} (${item.availableSeats} seats left)`}
                </option>
              ))}
            </select>
          )}
          {selectedItem && (
            <div style={{ fontSize: '12px', color: 'var(--success-text)', marginTop: '8px', fontWeight: '500' }}>
              ✓ {bookingType === 'hotel' ? `${selectedItem.availableRooms} Rooms` : `${selectedItem.availableSeats} Seats`} currently available
            </div>
          )}
        </div>

        <div className="d-field">
          <label className="d-label">{bookingType === 'hotel' ? 'Check-in Date' : 'Journey Date'}</label>
          <input
            className="d-input"
            name="journeyDate"
            type="date"
            min={minimumDate}
            value={journeyDate}
            onChange={(e) => setJourneyDate(e.target.value)}
            required
          />
        </div>

        <div className="d-field">
          <label className="d-label">{bookingType === 'hotel' ? 'Rooms' : 'Seats'}</label>
          <input
            className="d-input"
            name="totalSeats"
            type="number"
            min="1"
            max={bookingType === 'hotel' ? selectedItem?.availableRooms : selectedItem?.availableSeats}
            value={totalSeats}
            onChange={(e) => setTotalSeats(e.target.value)}
            required
          />
        </div>

        <div className="d-field span-2">
          <label className="d-label">Special Request</label>
          <textarea
            className="d-textarea"
            name="specialRequest"
            value={specialRequest}
            onChange={(e) => setSpecialRequest(e.target.value)}
            placeholder="Optional request"
          />
        </div>

        <div className="booking-total span-2">
          <span>Total Amount</span>
          <strong>Rs. {totalAmount}</strong>
        </div>

        <button className="d-btn brand span-2 booking-submit" disabled={loading}>
          {loading ? 'Booking...' : 'Confirm Booking'}
        </button>

        {message && <div className="d-message info span-2">{message}</div>}
      </div>
    </form>
  )
}

export default AddBooking

import { useEffect, useState } from 'react'
import { Search } from 'lucide-react'
import ConfirmAlert from '../components/ConfirmAlert'
import { useAuth } from '../customhooks/AuthContext'
import axiosInstance from '../utils/axiosInstance'

const API_URL = '/booking'

const BookingProfile = ({
  refreshKey = 0,
  type = '',
  adminMode = false,
  title = 'My Bookings',
}) => {
  const { token } = useAuth()
  const savedToken = token
  const [bookings, setBookings] = useState([])
  const [message, setMessage] = useState(savedToken ? '' : 'Please login first')
  const [loading, setLoading] = useState(Boolean(savedToken))

  // Search & Filter
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('all')
  const [typeFilter, setTypeFilter] = useState('all')
  const [sortBy, setSortBy] = useState('newest')

  // Confirm alert
  const [confirmAlert, setConfirmAlert] = useState(null)

  const getBookings = async () => {
    if (!token) {
      setMessage('Please login first')
      setLoading(false)
      return
    }
    try {
      setLoading(true)
      const url = type ? `${API_URL}/getbooking?type=${type}` : `${API_URL}/getbooking`
      const res = await axiosInstance.get(url)
      setBookings(res.data.bookings || [])
    } catch (error) {
      setMessage(error.response?.data?.message || 'Could not load bookings')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    let ignore = false
    if (!token) return undefined

    const url = type ? `${API_URL}/getbooking?type=${type}` : `${API_URL}/getbooking`
    axiosInstance.get(url)
      .then((res) => {
        if (!ignore) {
          setBookings(res.data.bookings || [])
          setLoading(false)
        }
      })
      .catch((error) => {
        if (!ignore) {
          setMessage(error.response?.data?.message || 'Could not load bookings')
          setLoading(false)
        }
      })

    return () => { ignore = true }
  }, [refreshKey, type])

  const updateBooking = async (booking, bookingStatus, paymentStatus) => {
    try {
      const endpoint = bookingStatus === 'Cancelled' ? 'cancelbooking' : 'confirmbooking'
      const res = await axiosInstance.put(
        `${API_URL}/${endpoint}/${booking._id}`,
        { cancellationReason: bookingStatus === 'Cancelled' ? 'Cancelled by user' : '' },
      )
      setBookings(bookings.map((item) =>
        item._id === booking._id ? res.data.booking : item
      ))
      setMessage(res.data.message)
    } catch (error) {
      setMessage(error.response?.data?.message || 'Could not update booking')
    }
  }

  const askCancelConfirm = (booking) => {
    setConfirmAlert({
      message: `Cancel your booking for "${getName(booking)}"? This cannot be undone.`,
      onConfirm: () => {
        setConfirmAlert(null)
        updateBooking(booking, 'Cancelled', booking.paymentStatus)
      }
    })
  }

  const askAdminConfirm = (booking, status) => {
    const isCancel = status === 'Cancelled'
    setConfirmAlert({
      message: isCancel
        ? `Cancel booking for "${getName(booking)}"?`
        : `Confirm and mark payment as Paid for "${getName(booking)}"?`,
      danger: isCancel,
      onConfirm: () => {
        setConfirmAlert(null)
        updateBooking(booking, status, status === 'Confirmed' ? 'Paid' : booking.paymentStatus)
      }
    })
  }

  const getName = (booking) => {
    if (booking.bookingType === 'hotel') return booking.hotel?.hotelName || 'Hotel'
    return booking.bus?.busName || 'Bus'
  }

  // Filter & Sort
  const filteredBookings = bookings
    .filter(b => {
      const q = search.toLowerCase()
      const name = getName(b).toLowerCase()
      const customerName = `${b.user?.firstName || ''} ${b.user?.lastName || ''}`.toLowerCase()
      const matchSearch = !q || name.includes(q) || customerName.includes(q)
      const matchStatus = statusFilter === 'all' || b.bookingStatus === statusFilter
      const matchType = typeFilter === 'all' || b.bookingType === typeFilter
      return matchSearch && matchStatus && matchType
    })
    .sort((a, b) => {
      if (sortBy === 'newest') return new Date(b.createdAt) - new Date(a.createdAt)
      if (sortBy === 'oldest') return new Date(a.createdAt) - new Date(b.createdAt)
      if (sortBy === 'amount-high') return (b.amount || 0) - (a.amount || 0)
      if (sortBy === 'amount-low') return (a.amount || 0) - (b.amount || 0)
      return 0
    })

  const containerVariants = {
    hidden: { opacity: 0 },
    show: {
      opacity: 1,
      transition: { staggerChildren: 0.1 }
    }
  }

  const itemVariants = {
    hidden: { opacity: 0, y: 15 },
    show: { opacity: 1, y: 0, transition: { type: 'spring', stiffness: 300, damping: 24 } }
  }

  return (
    <div className="panel">
      <div className="panel-header">
        <div className="panel-title-group">
          <span className="panel-eyebrow">Bookings</span>
          <h2 className="panel-title">{title}</h2>
          <p className="panel-desc">Total: {bookings.length} | Showing: {filteredBookings.length}</p>
        </div>
        <button className="d-btn ghost" type="button" onClick={getBookings}>Refresh</button>
      </div>

      {/* Search & Filter */}
      <div style={{ display: 'flex', flexWrap: 'wrap', gap: '12px', marginTop: '16px', marginBottom: '4px' }}>
        <div style={{ position: 'relative', flex: 1, minWidth: '200px' }}>
          <Search size={15} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
          <input
            className="d-input"
            placeholder={adminMode ? 'Search by hotel/bus or customer...' : 'Search bookings...'}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{ paddingLeft: '36px' }}
          />
        </div>
        <select className="d-select" value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)} style={{ minWidth: '140px' }}>
          <option value="all">All Status</option>
          <option value="Pending">Pending</option>
          <option value="Confirmed">Confirmed</option>
          <option value="Cancelled">Cancelled</option>
          <option value="Completed">Completed</option>
        </select>
        {!type && (
          <select className="d-select" value={typeFilter} onChange={(e) => setTypeFilter(e.target.value)} style={{ minWidth: '120px' }}>
            <option value="all">All Types</option>
            <option value="hotel">Hotel</option>
            <option value="bus">Bus</option>
          </select>
        )}
        <select className="d-select" value={sortBy} onChange={(e) => setSortBy(e.target.value)} style={{ minWidth: '150px' }}>
          <option value="newest">Newest First</option>
          <option value="oldest">Oldest First</option>
          <option value="amount-high">Amount: High to Low</option>
          <option value="amount-low">Amount: Low to High</option>
        </select>
      </div>

      {message && <div className="d-message info" style={{ marginTop: '12px' }}>{message}</div>}

      {loading ? (
        <div style={{ marginTop: '24px', display: 'flex', flexDirection: 'column', gap: '16px' }}>
          <div >Loading...</div>
          <div >Loading...</div>
          <div >Loading...</div>
        </div>
      ) : filteredBookings.length === 0 ? (
        <div className="empty-state">
          <p className="empty-state-title">No bookings found</p>
          <p className="empty-state-desc">{search || statusFilter !== 'all' ? 'Try changing filters.' : 'New bookings will appear here.'}</p>
        </div>
      ) : (
        <div className="booking-list" initial="hidden" animate="show">
          {filteredBookings.map((booking) => (
            <div className="booking-card card-animated" key={booking._id}>
              <div >
                <span className="booking-type">{booking.bookingType}</span>
                <h3>{getName(booking)}</h3>
                {adminMode && (
                  <p>
                    Customer: {booking.user?.firstName} {booking.user?.lastName}
                    {' '}({booking.user?.email})
                  </p>
                )}
                <p><strong>Journey Date:</strong> {new Date(booking.journeyDate).toLocaleDateString()}</p>
                <p><strong>Booked On:</strong> {new Date(booking.bookingDate || booking.createdAt).toLocaleDateString()}</p>
                <p><strong>{booking.bookingType === 'hotel' ? 'Rooms' : 'Seats'}:</strong> {booking.totalSeats}</p>
                <p><strong>Amount:</strong> Rs. {booking.amount}</p>
                {booking.specialRequest && (
                  <p style={{ fontStyle: 'italic', fontSize: '13px', marginTop: '6px', color: 'var(--text-muted)' }}>
                    <strong>Special Request:</strong> "{booking.specialRequest}"
                  </p>
                )}
                {booking.cancellationReason && (
                  <p style={{ color: 'var(--error-text)', fontSize: '13px', marginTop: '6px' }}>
                    <strong>Reason for Cancellation:</strong> {booking.cancellationReason}
                  </p>
                )}
                {booking.transactionId && (
                  <p style={{ fontFamily: 'monospace', fontSize: '12px', color: 'var(--text-muted)', marginTop: '4px' }}>
                    <strong>Transaction ID:</strong> {booking.transactionId}
                  </p>
                )}
              </div>

              <div className="booking-card-side">
                <span className={`status-badge ${booking.bookingStatus.toLowerCase()}`}>
                  {booking.bookingStatus}
                </span>
                <span className="booking-payment">Payment: {booking.paymentStatus}</span>

                {adminMode && booking.bookingStatus === 'Pending' ? (
                  <div className="booking-actions">
                    <button className="d-btn brand sm"
                      type="button"
                      onClick={() => askAdminConfirm(booking, 'Confirmed')}
                    >
                      Confirm
                    </button>
                    <button className="d-btn danger sm"
                      type="button"
                      onClick={() => askAdminConfirm(booking, 'Cancelled')}
                    >
                      Cancel
                    </button>
                  </div>
                ) : !adminMode && booking.bookingStatus === 'Pending' ? (
                  <button className="d-btn danger sm" type="button" onClick={() => askCancelConfirm(booking)}>
                    Cancel Booking
                  </button>
                ) : null}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Confirm Alert */}
      {confirmAlert && (
        <ConfirmAlert
          message={confirmAlert.message}
          danger={confirmAlert.danger !== false}
          onConfirm={confirmAlert.onConfirm}
          onCancel={() => setConfirmAlert(null)}
        />
      )}
    </div>
  )
}

export default BookingProfile

import axios from 'axios'
import { Edit3, KeyRound, Mail, Phone, RotateCcw, Save, UserRound, X } from 'lucide-react'
import { useEffect, useState } from 'react'
import LazyImage from '../components/LazyImage'
import { useAuth } from '../customhooks/AuthContext'
import axiosInstance from '../utils/axiosInstance'

const API_URL = '/user'

const UserProfile = () => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    gender: '',
    profileImage: '',
  })
  const [savedProfile, setSavedProfile] = useState(null)
  const [profileImageFile, setProfileImageFile] = useState(null)
  const [profileImagePreview, setProfileImagePreview] = useState('')
  const [isEditing, setIsEditing] = useState(false)
  const [passwordData, setPasswordData] = useState({
    oldPassword: '',
    newPassword: '',
  })
  const [isPasswordModalOpen, setIsPasswordModalOpen] = useState(false)
  const [message, setMessage] = useState('')
  const [passwordMessage, setPasswordMessage] = useState('')
  const [loading, setLoading] = useState(false)

  const { token, updateUser } = useAuth()
  const userName = `${formData.firstName || 'Traveler'} ${formData.lastName || ''}`
  const avatarText = `${formData.firstName?.[0] || 'T'}${formData.lastName?.[0] || 'U'}`
  const displayImage = profileImagePreview || formData.profileImage

  const getProfile = async () => {
    try {
      const res = await axiosInstance.get(`${API_URL}/profile`)
      const profile = {
        firstName: res.data.user.firstName || '',
        lastName: res.data.user.lastName || '',
        email: res.data.user.email || '',
        phone: res.data.user.phone || '',
        gender: res.data.user.gender || '',
        profileImage: res.data.user.profileImage || '',
      }
      setFormData(profile)
      setSavedProfile(profile)
      setProfileImageFile(null)
      setProfileImagePreview('')
    } catch (error) {
      setMessage(error.response?.data?.message || 'Profile load failed')
    }
  }

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value })
  }

  const handleProfileImageChange = (e) => {
    const file = e.target.files[0]
    if (!file) return
    setProfileImageFile(file)
    setProfileImagePreview(URL.createObjectURL(file))
  }

  const resetProfileForm = () => {
    if (savedProfile) setFormData(savedProfile)
    setProfileImageFile(null)
    setProfileImagePreview('')
    setMessage('')
  }

  const cancelEdit = () => {
    resetProfileForm()
    setIsEditing(false)
  }

  const updateProfile = async (e) => {
    e.preventDefault()
    setMessage('')
    setLoading(true)

    try {
      const profileData = new FormData()
      Object.keys(formData).forEach((key) => {
        if (key !== 'profileImage') profileData.append(key, formData[key])
      })
      if (profileImageFile) profileData.append('profileImage', profileImageFile)

      const res = await axiosInstance.put(`${API_URL}/updateprofile`, profileData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      })

      updateUser(res.data.user)
      const updated = {
        firstName: res.data.user.firstName || '',
        lastName: res.data.user.lastName || '',
        email: res.data.user.email || '',
        phone: res.data.user.phone || '',
        gender: res.data.user.gender || '',
        profileImage: res.data.user.profileImage || '',
      }
      setFormData(updated)
      setSavedProfile(updated)
      setProfileImageFile(null)
      setProfileImagePreview('')
      setIsEditing(false)
      setMessage(res.data.message)
    } catch (error) {
      setMessage(error.response?.data?.message || 'Profile update failed')
    } finally {
      setLoading(false)
    }
  }

  const changePassword = async (e) => {
    e.preventDefault()
    setPasswordMessage('')

    try {
      const res = await axiosInstance.put(`${API_URL}/changepassword`, passwordData)
      setPasswordMessage(res.data.message)
      setPasswordData({ oldPassword: '', newPassword: '' })
      setIsPasswordModalOpen(false)
    } catch (error) {
      setPasswordMessage(error.response?.data?.message || 'Password change failed')
    }
  }

  useEffect(() => {
    getProfile()
  }, [])

  return (
    <div className="profile-layout">
      {/* ── Sidebar ── */}
      <div className="profile-sidebar">
        <div className="profile-avatar-wrap">
          {displayImage ? (
            <LazyImage className="profile-avatar" src={displayImage} alt={userName} />
          ) : (
            <div className="profile-avatar-initials">{avatarText}</div>
          )}
        </div>

        <h2 className="profile-name">{userName}</h2>
        <span className="profile-role">
          <UserRound size={14} />
          Traveler
        </span>

        <div className="profile-sidebar-actions">
          <button className="d-btn brand" type="button" onClick={() => setIsEditing(true)}>
            <Edit3 size={15} />
            Edit Profile
          </button>
          <button className="d-btn ghost" type="button" onClick={() => { setPasswordMessage(''); setIsPasswordModalOpen(true) }}>
            <KeyRound size={15} />
            Reset Password
          </button>
        </div>

        <div className="profile-meta-list">
          <div className="profile-meta-item">
            <Mail size={15} />
            <span>{formData.email || 'No email'}</span>
          </div>
          <div className="profile-meta-item">
            <Phone size={15} />
            <span>{formData.phone || 'No phone'}</span>
          </div>
        </div>
      </div>

      {/* ── Right panel ── */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
        <form className="panel" onSubmit={updateProfile}>
          <div className="panel-header">
            <div className="panel-title-group">
              <span className="panel-eyebrow">Account</span>
              <h2 className="panel-title">{isEditing ? 'Edit Profile' : 'Profile Details'}</h2>
            </div>
            {isEditing && (
              <div className="panel-actions">
                <button className="d-btn ghost" type="button" onClick={resetProfileForm}>
                  <RotateCcw size={15} />
                  Reset
                </button>
                <button className="d-btn ghost" type="button" onClick={cancelEdit}>
                  <X size={15} />
                  Cancel
                </button>
              </div>
            )}
          </div>

          <div className="d-form cols-2">
            <div className="d-field">
              <label className="d-label">First Name</label>
              <div className="d-input-wrapper">
                <span className="d-input-icon"><UserRound size={16} /></span>
                <input
                  className="d-input with-icon"
                  name="firstName"
                  value={formData.firstName}
                  onChange={handleChange}
                  disabled={!isEditing}
                  required
                />
              </div>
            </div>

            <div className="d-field">
              <label className="d-label">Last Name</label>
              <input className="d-input" name="lastName" value={formData.lastName} onChange={handleChange} disabled={!isEditing} required />
            </div>

            <div className="d-field">
              <label className="d-label">Email</label>
              <input className="d-input" name="email" type="email" value={formData.email} onChange={handleChange} disabled={!isEditing} required />
            </div>

            <div className="d-field">
              <label className="d-label">Phone</label>
              <input className="d-input" name="phone" value={formData.phone} onChange={handleChange} disabled={!isEditing} />
            </div>

            <div className="d-field">
              <label className="d-label">Gender</label>
              <select className="d-select" name="gender" value={formData.gender} onChange={handleChange} disabled={!isEditing}>
                <option value="">Select Gender</option>
                <option value="Male">Male</option>
                <option value="Female">Female</option>
                <option value="Other">Other</option>
              </select>
            </div>

            {isEditing && (
              <div className="d-field">
                <label className="d-label">Upload Profile Image</label>
                <input className="d-file" type="file" accept="image/*" onChange={handleProfileImageChange} />
              </div>
            )}
          </div>

          {isEditing && (
            <button className="d-btn brand" style={{ marginTop: '20px' }} disabled={loading}>
              <Save size={16} />
              {loading ? 'Saving…' : 'Save Profile'}
            </button>
          )}

          {message && <div className="d-message info" style={{ marginTop: '16px' }}>{message}</div>}
        </form>

        {passwordMessage && <div className="d-message info">{passwordMessage}</div>}
      </div>

      {/* ── Change password modal ── */}
      {isPasswordModalOpen && (
        <div className="modal-overlay">
          <form className="modal-box" onSubmit={changePassword}>
            <div className="modal-header">
              <div>
                <p className="modal-eyebrow">Security</p>
                <h2 className="modal-title">Reset Password</h2>
              </div>
              <button
                className="modal-close"
                type="button"
                onClick={() => { setIsPasswordModalOpen(false); setPasswordData({ oldPassword: '', newPassword: '' }) }}
              >
                <X size={18} />
              </button>
            </div>

            <div className="d-form">
              <div className="d-field">
                <label className="d-label">Old Password</label>
                <input
                  className="d-input"
                  type="password"
                  value={passwordData.oldPassword}
                  onChange={(e) => setPasswordData({ ...passwordData, oldPassword: e.target.value })}
                  required
                />
              </div>
              <div className="d-field">
                <label className="d-label">New Password</label>
                <input
                  className="d-input"
                  type="password"
                  value={passwordData.newPassword}
                  onChange={(e) => setPasswordData({ ...passwordData, newPassword: e.target.value })}
                  required
                />
              </div>
            </div>

            <div className="modal-footer">
              <button
                className="d-btn ghost"
                type="button"
                onClick={() => { setIsPasswordModalOpen(false); setPasswordData({ oldPassword: '', newPassword: '' }) }}
              >
                <X size={16} />
                Cancel
              </button>
              <button className="d-btn brand" type="submit">
                <KeyRound size={16} />
                Update Password
              </button>
            </div>

            {passwordMessage && <div className="d-message info" style={{ marginTop: '16px' }}>{passwordMessage}</div>}
          </form>
        </div>
      )}
    </div>
  )
}

export default UserProfile

import React, { useEffect, useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import axiosInstance from '../utils/axiosInstance';
import { ArrowLeft, Star, MapPin, CheckCircle, Bus as BusIcon, Clock, ArrowUpDown } from 'lucide-react';
import AddBooking from '../booking/Addbboking';
import { useAuth } from '../customhooks/AuthContext';

const BusDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { token } = useAuth();
  const isLoggedIn = Boolean(token);

  const [bus, setBus] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Booking modal
  const [isBookingOpen, setIsBookingOpen] = useState(false);

  useEffect(() => {
    const fetchBus = async () => {
      try {
        const response = await axiosInstance.get(`/bus/get/${id}`);
        if (response.data.bus) {
          setBus(response.data.bus);
        } else {
          setError(response.data.message || 'Bus not found');
        }
      } catch (err) {
        console.error('Error fetching bus:', err);
        setError('Failed to load bus details');
      } finally {
        setLoading(false);
      }
    };
    fetchBus();
  }, [id]);

  if (loading) {
    return (
      <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: 'var(--bg-base)', color: 'var(--text-body)' }}>
        <p>Loading bus details...</p>
      </div>
    );
  }

  if (error || !bus) {
    return (
      <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', backgroundColor: 'var(--bg-base)', color: 'var(--text-body)', gap: '16px' }}>
        <p>{error || 'Bus not found'}</p>
        <button className="d-btn brand" onClick={() => navigate('/')}>Go Back Home</button>
      </div>
    );
