import { Link, useNavigate } from 'react-router-dom'
import {
  ArrowRight, Hotel, ShieldCheck, Star, MapPin,
  ArrowUpDown, Sun, Moon, Phone, Mail, Globe,
  TreePine, Mountain, Waves, Bus, Compass,
