import React, { useState, useEffect } from 'react'
import { PlusCircle, Edit3, Trash2, Eye, X } from 'lucide-react'
import LazyImage from '../components/LazyImage'
import { useAuth } from '../customhooks/AuthContext'
import axiosInstance from '../utils/axiosInstance'

const GetOperatorBuses = ({ operatorData, onAddBus, onEditBus }) => {
  const [buses, setBuses] = useState([])
  const [loading, setLoading] = useState(true)
  const [selectedBus, setSelectedBus] = useState(null)

  const { token } = useAuth()

  const fetchBuses = async () => {
    try {
      const res = await axiosInstance.get('/bus/get')

      let allBuses = res.data.buses || []

      if (operatorData?._id) {
        allBuses = allBuses.filter(b => b.operatorName === operatorData._id || (b.operatorName && b.operatorName._id === operatorData._id))
      }

      setBuses(allBuses)
    } catch (err) {
      console.error(err)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchBuses()
  }, [operatorData])

  const handleDelete = async (busId) => {
    if (window.confirm('Are you sure you want to delete this bus?')) {
      try {
        await axiosInstance.delete(`/bus/delete/${busId}`)
        fetchBuses()
      } catch (error) {
        alert(error.response?.data?.message || 'Failed to delete bus')
      }
    }
  }

  if (loading) return <div style={{ padding: '24px' }}>Loading buses...</div>

  return (
    <div className="panel" style={{ padding: '24px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
        <h2 style={{ fontSize: '20px', fontWeight: 'bold', color: 'var(--text-heading)' }}>My Fleet</h2>

        <button 
          onClick={onAddBus}
          className="d-btn brand"
          style={{ width: 'max-content' }}
        >
          <PlusCircle size={18} /> Add New Bus
        </button>
      </div>

      {buses.length > 0 ? (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '20px' }}>
          {buses.map(bus => (
            <div key={bus._id} style={{ border: '1px solid var(--border-subtle)', borderRadius: '12px', overflow: 'hidden', background: 'var(--bg-base)' }}>
              <div style={{ height: '160px', width: '100%' }}>
                {bus.images && bus.images.length > 0 ? (
                  <LazyImage src={bus.images[0]} alt={bus.busName} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                ) : (
                  <div style={{ width: '100%', height: '100%', background: 'var(--brand-gradient)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold' }}>
                    {bus.busName}
                  </div>
                )}
              </div>
              <div style={{ padding: '16px' }}>
                <h3 style={{ margin: '0 0 4px', fontSize: '18px', fontWeight: 'bold' }}>{bus.busName}</h3>
                <p style={{ margin: '0 0 8px', fontSize: '14px', color: 'var(--text-muted)' }}>{bus.busNumber} • {bus.busType}</p>

                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px', fontSize: '14px' }}>
                  <span>{bus.fromCityID?.city || 'Unknown'} → {bus.toCityID?.city || 'Unknown'}</span>
                </div>

                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '16px' }}>
                  <span style={{ fontSize: '16px', fontWeight: 'bold', color: 'var(--brand-from)' }}>₹{bus.fare}</span>
                  <div style={{ display: 'flex', gap: '8px' }}>
                    <button onClick={() => setSelectedBus(bus)} style={{ background: 'none', border: 'none', color: 'var(--brand-from)', cursor: 'pointer', padding: '4px' }} title="View Bus Details">
                      <Eye size={18} />
                    </button>
                    <button onClick={() => onEditBus(bus)} style={{ background: 'none', border: 'none', color: 'var(--brand-primary)', cursor: 'pointer', padding: '4px' }} title="Edit Bus">
                      <Edit3 size={18} />
                    </button>
                    <button onClick={() => handleDelete(bus._id)} style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', padding: '4px' }} title="Delete Bus">
                      <Trash2 size={18} />
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div style={{ padding: '40px 20px', textAlign: 'center', background: 'var(--bg-base)', borderRadius: '12px', border: '1px dashed var(--border-subtle)' }}>
          <p style={{ color: 'var(--text-muted)', marginBottom: '16px' }}>No buses added yet.</p>
        </div>
      )}

      {selectedBus && (
        <div className="modal-overlay" style={{ zIndex: 1000 }}>
          <div className="modal-box" style={{ maxWidth: '600px', maxHeight: '90vh', overflowY: 'auto' }}>
            <div className="modal-header">
              <div>
                <p className="modal-eyebrow">{selectedBus.busType}</p>
                <h2 className="modal-title">{selectedBus.busName} ({selectedBus.busNumber})</h2>
              </div>
              <button className="modal-close" onClick={() => setSelectedBus(null)}><X size={18} /></button>
            </div>

            <div style={{ padding: '24px' }}>
              <div style={{ height: '200px', width: '100%', marginBottom: '20px', borderRadius: '8px', overflow: 'hidden' }}>
                {selectedBus.images && selectedBus.images.length > 0 ? (
                  <LazyImage src={selectedBus.images[0]} alt={selectedBus.busName} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                ) : (
                  <div style={{ width: '100%', height: '100%', background: 'var(--brand-gradient)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold' }}>
                    No Image Available
                  </div>
                )}
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '24px' }}>
                <div>
                  <p style={{ fontSize: '12px', color: 'var(--text-muted)', margin: '0 0 4px' }}>Route</p>
                  <p style={{ fontWeight: '500', margin: 0 }}>{selectedBus.fromCityID?.city} → {selectedBus.toCityID?.city}</p>
                </div>
                <div>
                  <p style={{ fontSize: '12px', color: 'var(--text-muted)', margin: '0 0 4px' }}>Fare</p>
                  <p style={{ fontWeight: 'bold', margin: 0, color: 'var(--brand-from)' }}>₹{selectedBus.fare}</p>
                </div>
                <div>
                  <p style={{ fontSize: '12px', color: 'var(--text-muted)', margin: '0 0 4px' }}>Total Seats / Available</p>
                  <p style={{ fontWeight: '500', margin: 0 }}>{selectedBus.totalSeats} / {selectedBus.availableSeats}</p>
                </div>
                <div>
                  <p style={{ fontSize: '12px', color: 'var(--text-muted)', margin: '0 0 4px' }}>Duration</p>
                  <p style={{ fontWeight: '500', margin: 0 }}>{selectedBus.duration || 'Not specified'}</p>
                </div>
              </div>

              {selectedBus.amenities && selectedBus.amenities.length > 0 && (
                <div style={{ marginBottom: '24px' }}>
                  <h4 style={{ fontSize: '14px', fontWeight: 'bold', marginBottom: '8px' }}>Amenities</h4>
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                    {selectedBus.amenities.map((amenity, idx) => (
                      <span key={idx} style={{ background: 'var(--bg-elevated)', border: '1px solid var(--border-subtle)', padding: '4px 10px', borderRadius: '100px', fontSize: '12px' }}>
                        {amenity}
                      </span>
                    ))}
                  </div>
                </div>
              )}

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
                <div>
                  <h4 style={{ fontSize: '14px', fontWeight: 'bold', marginBottom: '8px' }}>Boarding Points</h4>
                  {selectedBus.boardingPoints && selectedBus.boardingPoints.length > 0 ? (
                    <ul style={{ paddingLeft: '20px', margin: 0, fontSize: '13px' }}>
                      {selectedBus.boardingPoints.map((point, idx) => (
                        <li key={idx}>{point.name}</li>
                      ))}
                    </ul>
                  ) : <p style={{ fontSize: '13px', color: 'var(--text-muted)', margin: 0 }}>None specified</p>}
                </div>
                <div>
                  <h4 style={{ fontSize: '14px', fontWeight: 'bold', marginBottom: '8px' }}>Dropping Points</h4>
                  {selectedBus.droppingPoints && selectedBus.droppingPoints.length > 0 ? (
                    <ul style={{ paddingLeft: '20px', margin: 0, fontSize: '13px' }}>
                      {selectedBus.droppingPoints.map((point, idx) => (
                        <li key={idx}>{point.name}</li>
                      ))}
                    </ul>
                  ) : <p style={{ fontSize: '13px', color: 'var(--text-muted)', margin: 0 }}>None specified</p>}
                </div>
              </div>
            </div>

            <div className="modal-footer">
              <button className="d-btn brand" onClick={() => setSelectedBus(null)} style={{ width: '100%', justifyContent: 'center' }}>Close</button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default GetOperatorBuses

import React, { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { Bus, UserCircle, LogOut, LayoutDashboard, PlusCircle, Sun, Moon, Map, CheckSquare, Clock, TrendingUp } from 'lucide-react'
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts'
import { useAuth } from '../customhooks/AuthContext'
import axiosInstance from '../utils/axiosInstance'
import Operatorprofile from './Operatorprofile'
import AddOperatorBuses from './AddOperatorBuses'
import GetOperatorBuses from './GetOperatorBuses'
import { useTheme } from '../customhooks/ThemeContext'
import BookingProfile from '../booking/BookingProfile'
import ConfirmAlert from '../components/ConfirmAlert'

const OperatorDash = () => {
  const navigate = useNavigate()
  const { theme, toggleTheme } = useTheme()
  const [activeTab, setActiveTab] = useState('dashboard')
  const [operatorData, setOperatorData] = useState(null)
  const [editBusData, setEditBusData] = useState(null)
  const [logoutConfirm, setLogoutConfirm] = useState(false)
  const [dashboardStats, setDashboardStats] = useState({ totalBuses: 0, activeBuses: 0, totalBookings: 0, pendingBookings: 0, confirmedBookings: 0, cancelledBookings: 0, totalRevenue: 0 })
  
  const { user: savedUser, token, logout: authLogout } = useAuth()

  const fetchDashboardStats = async (operatorId) => {
    try {
      // Fetch Buses
      const busRes = await axiosInstance.get('/bus/get')
      const allBuses = busRes.data.buses || []
      const myBuses = allBuses.filter(b => b.operatorName === operatorId || (b.operatorName && b.operatorName._id === operatorId))
      const activeBuses = myBuses.filter(b => b.isActive).length

      // Fetch Bookings
      const bookingRes = await axiosInstance.get('/booking/getbooking?type=bus')
      const myBookings = bookingRes.data.bookings || []
      
      let pending = 0, confirmed = 0, cancelled = 0, revenue = 0;
      myBookings.forEach(b => {
        if (b.bookingStatus === 'Pending') pending++
        if (b.bookingStatus === 'Confirmed') {
          confirmed++
          revenue += (b.amount || 0)
        }
        if (b.bookingStatus === 'Cancelled') cancelled++
      })

      setDashboardStats({
        totalBuses: myBuses.length,
        activeBuses,
        totalBookings: myBookings.length,
        pendingBookings: pending,
        confirmedBookings: confirmed,
        cancelledBookings: cancelled,
        totalRevenue: revenue
      })
    } catch (err) {
      console.error('Error fetching stats:', err)
    }
  }

  useEffect(() => {
    if (!token) {
      navigate('/login')
      return
    }
    const fetchOperator = async () => {
      try {
        const res = await axiosInstance.get('/operator/get')
        setOperatorData(res.data.operator)
        if (res.data.operator) {
          fetchDashboardStats(res.data.operator._id)
        }
      } catch (err) {
        console.error(err)
      }
    }
    
    if (!operatorData) {
      fetchOperator()
    } else if (activeTab === 'dashboard') {
      fetchDashboardStats(operatorData._id)
    }
  }, [token, navigate, activeTab, operatorData])

  const logout = () => {
    authLogout()
    navigate('/')
  }

  const graphData = [
    { name: 'Pending', count: dashboardStats.pendingBookings, fill: '#f59e0b' },
    { name: 'Confirmed', count: dashboardStats.confirmedBookings, fill: '#10b981' },
    { name: 'Cancelled', count: dashboardStats.cancelledBookings, fill: '#ef4444' }
  ]

  return (
    <div className="admin-page">
      <nav className="admin-navbar">
        <div className="admin-navbar-inner">
          <div className="admin-brand">
            <span className="admin-brand-icon"><Bus size={20} /></span>
            <span>
              <span className="admin-brand-name">JourneyHub Bus</span>
              <span className="admin-brand-sub">Operator Dashboard</span>
            </span>
          </div>
          
          <div className="admin-nav-actions" style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <button className="theme-toggle" onClick={toggleTheme} title="Toggle theme">
              {theme === 'dark' ? <Sun size={18} /> : <Moon size={18} />}
            </button>
            <button className="admin-nav-btn ghost" onClick={() => setActiveTab('profile')}>
              <UserCircle size={17} /> {savedUser.firstName || 'Profile'}
            </button>
            <button className="admin-nav-btn danger" onClick={() => setLogoutConfirm(true)}>
              <LogOut size={16} /> Logout
            </button>
          </div>
        </div>
      </nav>

      <main className="admin-main">
        <div className="admin-tabs">
          <button className={`admin-tab ${activeTab === 'dashboard' ? 'active' : ''}`} onClick={() => setActiveTab('dashboard')}>
            <LayoutDashboard size={16} /> Dashboard
          </button>
          <button className={`admin-tab ${activeTab === 'bookings' ? 'active' : ''}`} onClick={() => setActiveTab('bookings')}>
            <Bus size={16} /> Ticket Bookings
          </button>
          <button className={`admin-tab ${activeTab === 'buses' ? 'active' : ''}`} onClick={() => setActiveTab('buses')}>
            <Bus size={16} /> My Buses
          </button>
          <button className={`admin-tab ${activeTab === 'profile' ? 'active' : ''}`} onClick={() => setActiveTab('profile')}>
            <UserCircle size={16} /> My Agency Profile
          </button>
        </div>
          {(!operatorData?.isApproved && savedUser.role === 'bus_admin') && (
            <div style={{ background: 'rgba(245, 158, 11, 0.1)', borderLeft: '4px solid #f59e0b', padding: '16px', borderRadius: '8px', marginBottom: '24px', display: 'flex', alignItems: 'center', gap: '12px' }}>
              <span style={{ fontSize: '24px' }}>⏳</span>
              <div>
                <h4 style={{ color: '#f59e0b', margin: '0 0 4px', fontWeight: 'bold' }}>Account Pending Approval</h4>
                <p style={{ margin: 0, color: 'var(--text-muted)', fontSize: '14px' }}>Your operator account is currently under review by the Super Admin. You cannot add buses until approved.</p>
              </div>
            </div>
          )}

          {activeTab === 'dashboard' && (
            <div className="admin-dashboard-content">
              <div className="panel" style={{ padding: '24px', marginBottom: '24px' }}>
                <h2 style={{ fontSize: '24px', fontWeight: 'bold', color: 'var(--text-heading)', marginBottom: '8px' }}>Welcome, {operatorData?.agencyName || 'Operator'}!</h2>
                <p style={{ color: 'var(--text-body)', margin: 0 }}>Manage your buses, routes, and tickets from this dashboard.</p>
              </div>

              <h3 style={{ marginBottom: '16px', color: 'var(--text-heading)', fontSize: '18px', fontWeight: '700' }}>Fleet Overview</h3>
              <div className="dash-stats-grid" style={{ marginBottom: '32px' }}>
                <div className="dash-stat card-animated" onClick={() => setActiveTab('buses')}>
                  <div className="dash-stat-header">
                    <span className="dash-stat-label">Total Buses</span>
                    <span className="dash-stat-icon indigo"><Bus size={18} /></span>
                  </div>
                  <div className="dash-stat-value">{dashboardStats.totalBuses}</div>
                  <button className="dash-stat-action">Manage Fleet →</button>
                </div>

                <div className="dash-stat card-animated" onClick={() => setActiveTab('buses')}>
                  <div className="dash-stat-header">
                    <span className="dash-stat-label">Active Routes</span>
                    <span className="dash-stat-icon emerald"><Map size={18} /></span>
                  </div>
                  <div className="dash-stat-value">{dashboardStats.activeBuses}</div>
                  <button className="dash-stat-action">Currently running</button>
                </div>
              </div>

              <h3 style={{ marginBottom: '16px', color: 'var(--text-heading)', fontSize: '18px', fontWeight: '700' }}>Booking Statistics</h3>
              <div className="dash-stats-grid">
                <div className="dash-stat card-animated" onClick={() => setActiveTab('bookings')}>
                  <div className="dash-stat-header">
                    <span className="dash-stat-label">Total Bookings</span>
                    <span className="dash-stat-icon indigo"><CheckSquare size={18} /></span>
                  </div>
                  <div className="dash-stat-value">{dashboardStats.totalBookings}</div>
                  <button className="dash-stat-action">View all →</button>
                </div>

                <div className="dash-stat card-animated" onClick={() => setActiveTab('bookings')}>
                  <div className="dash-stat-header">
                    <span className="dash-stat-label">Pending Approval</span>
                    <span className="dash-stat-icon amber"><Clock size={18} /></span>
                  </div>
                  <div className="dash-stat-value">{dashboardStats.pendingBookings}</div>
                  <button className="dash-stat-action">Requires action</button>
                </div>

                <div className="dash-stat card-animated">
                  <div className="dash-stat-header">
                    <span className="dash-stat-label">Total Revenue</span>
                    <span className="dash-stat-icon emerald"><TrendingUp size={18} /></span>
                  </div>
                  <div className="dash-stat-value">₹{dashboardStats.totalRevenue.toLocaleString()}</div>
                  <button className="dash-stat-action" style={{ cursor: 'default' }}>From confirmed bookings</button>
                </div>
              </div>

              <div style={{ marginTop: '32px', background: 'var(--bg-surface)', padding: '24px', borderRadius: '16px', border: '1px solid var(--border-subtle)' }}>
                <h3 style={{ fontSize: '18px', fontWeight: '700', color: 'var(--text-heading)', marginBottom: '24px' }}>Booking Trends</h3>
                <div style={{ width: '100%', height: '300px' }}>
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={graphData} margin={{ top: 20, right: 30, left: 0, bottom: 5 }}>
                      <CartesianGrid strokeDasharray="3 3" stroke="var(--border-subtle)" vertical={false} />
                      <XAxis dataKey="name" tick={{ fill: 'var(--text-muted)', fontSize: 12 }} axisLine={false} tickLine={false} />
                      <YAxis tick={{ fill: 'var(--text-muted)', fontSize: 12 }} axisLine={false} tickLine={false} />
                      <Tooltip 
                        cursor={{ fill: 'rgba(255,255,255,0.05)' }}
                        contentStyle={{ backgroundColor: 'var(--bg-base)', border: '1px solid var(--border-subtle)', borderRadius: '8px', color: 'var(--text-body)' }}
                      />
                      <Bar dataKey="count" radius={[6, 6, 0, 0]}>
                        {graphData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={entry.fill} />
                        ))}
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'profile' && <Operatorprofile operatorData={operatorData} />}
          {activeTab === 'buses' && <GetOperatorBuses operatorData={operatorData} onAddBus={() => { setEditBusData(null); setActiveTab('add-bus'); }} onEditBus={(bus) => { setEditBusData(bus); setActiveTab('add-bus'); }} />}
          {activeTab === 'add-bus' && <AddOperatorBuses isApproved={operatorData?.isApproved} operatorId={operatorData?._id} editBusData={editBusData} onCancel={() => setActiveTab('buses')} />}
          {activeTab === 'bookings' && <BookingProfile type="bus" adminMode={true} title="Manage Bus Bookings" />}
        </main>

        {logoutConfirm && (
          <ConfirmAlert
            message="Are you sure you want to log out of your Operator Dashboard?"
            onConfirm={logout}
            onCancel={() => setLogoutConfirm(false)}
          />
        )}
    </div>
  )
}

export default OperatorDash

import { Bus, Edit3, IndianRupee, Plus, RefreshCw, Search, Trash2, X } from 'lucide-react'
import { useEffect, useState } from 'react'
import ConfirmAlert from '../components/ConfirmAlert'
import LazyImage from '../components/LazyImage'
import { useAuth } from '../customhooks/AuthContext'
import axiosInstance from '../utils/axiosInstance'

const API_URL = '/bus'

const blankForm = {
  busName: '',
  busNumber: '',
  operatorName: '',
  busType: 'AC Sleeper',
  fromCityID: '',
  toCityID: '',
  duration: '',
  totalSeats: '',
  availableSeats: '',
  fare: '',
}

const AddBus = () => {
  const [formData, setFormData] = useState(blankForm)
  const [amenities, setAmenities] = useState('')
  const [boardingPoints, setBoardingPoints] = useState('')
  const [droppingPoints, setDroppingPoints] = useState('')
  const [images, setImages] = useState(null)
  const [locations, setLocations] = useState([])
  const [buses, setBuses] = useState([])
  const [message, setMessage] = useState('')
  const [loading, setLoading] = useState(false)
  const [isFormOpen, setIsFormOpen] = useState(false)
  const [editId, setEditId] = useState('')

  // Search & Sort
  const [search, setSearch] = useState('')
  const [sortBy, setSortBy] = useState('newest')

  // Confirm Alert
  const [confirmAlert, setConfirmAlert] = useState(null)

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value })
  }

  const { token } = useAuth()

  const getToken = () => {
    return token
  }

  const getLocations = async () => {
    try {
      const res = await axiosInstance.get('/location/get')
      setLocations(res.data.locations || [])
    } catch (error) {
      setMessage(error.response?.data?.message || 'Location load failed')
    }
  }

  const getBuses = async () => {
    try {
      const res = await axiosInstance.get(`${API_URL}/get`)
      setBuses(res.data.buses || [])
    } catch (error) {
      setMessage(error.response?.data?.message || 'Bus load failed')
    }
  }

  const resetForm = () => {
    setFormData(blankForm)
    setAmenities('')
    setBoardingPoints('')
    setDroppingPoints('')
    setImages(null)
    setEditId('')
  }

  const openAddForm = () => {
    resetForm()
    setMessage('')
    setIsFormOpen(true)
  }

  const formatDate = (dateValue) => {
    if (!dateValue) {
      return ''
    }

    const date = new Date(dateValue)
    const offset = date.getTimezoneOffset() * 60000
    return new Date(date.getTime() - offset).toISOString().slice(0, 16)
  }

  const openEditForm = (bus) => {
    setFormData({
      busName: bus.busName || '',
      busNumber: bus.busNumber || '',
      operatorName: bus.operatorName || '',
      busType: bus.busType || 'AC Sleeper',
      fromCityID: bus.fromCityID?._id || bus.fromCityID || '',
      toCityID: bus.toCityID?._id || bus.toCityID || '',
      duration: bus.duration || '',
      totalSeats: bus.totalSeats || '',
      availableSeats: bus.availableSeats || '',
      fare: bus.fare || '',
    })

    setAmenities((bus.amenities || []).join(', '))
    setBoardingPoints((bus.boardingPoints || []).map((point) => point.name).join(', '))
    setDroppingPoints((bus.droppingPoints || []).map((point) => point.name).join(', '))
    setImages(null)
    setEditId(bus._id)
    setMessage('')
    setIsFormOpen(true)
  }

  const makeNameList = (text) => {
    return text
      .split(',')
      .map((name) => name.trim())
      .filter(Boolean)
      .map((name) => ({ name }))
  }

  const showPlace = (place) => {
    if (!place) {
      return ''
    }

    if (typeof place === 'string') {
      return place
    }

    return `${place.city}, ${place.state}`
  }

  const saveBus = async (e) => {
    e.preventDefault()

    const token = getToken()
    if (!token) {
      setMessage('Please login first')
      return
    }

    try {
      setLoading(true)
      setMessage('')

      const busData = new FormData()

      Object.keys(formData).forEach((key) => {
        busData.append(key, formData[key])
      })

      busData.append('amenities', amenities)
      busData.append('boardingPoints', JSON.stringify(makeNameList(boardingPoints)))
      busData.append('droppingPoints', JSON.stringify(makeNameList(droppingPoints)))

      if (images) {
        for (let i = 0; i < images.length; i += 1) {
          busData.append('images', images[i])
        }
      }

      const config = {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      }

      let res

      if (editId) {
        res = await axiosInstance.put(`${API_URL}/update/${editId}`, busData, config)
        setBuses(buses.map((bus) => (bus._id === editId ? res.data.bus : bus)))
      } else {
        res = await axiosInstance.post(`${API_URL}/add`, busData, config)
        setBuses([res.data.bus, ...buses])
      }

      setMessage(res.data.message)
      resetForm()
      setIsFormOpen(false)
    } catch (error) {
      setMessage(error.response?.data?.message || 'Bus save failed')
    } finally {
      setLoading(false)
    }
  }

  const askDeleteConfirm = (bus) => {
    setConfirmAlert({
      message: `Delete bus "${bus.busName}"? This action cannot be undone.`,
      onConfirm: async () => {
        setConfirmAlert(null)
        const token = getToken()
        if (!token) {
          setMessage('Please login first')
          return
        }
        try {
          const res = await axiosInstance.delete(`${API_URL}/delete/${bus._id}`)
          setMessage(res.data.message)
          setBuses(buses.filter((b) => b._id !== bus._id))
        } catch (error) {
          setMessage(error.response?.data?.message || 'Bus delete failed')
        }
      }
    })
  }

  useEffect(() => {
    getLocations()
    getBuses()
  }, [])

  const filteredBuses = buses
    .filter(bus => {
      const q = search.toLowerCase()
      if (!q) return true
      return (bus.busName || '').toLowerCase().includes(q) || 
             (bus.operatorName || '').toLowerCase().includes(q) ||
             (bus.busNumber || '').toLowerCase().includes(q)
    })
    .sort((a, b) => {
      if (sortBy === 'newest') return new Date(b.createdAt || Date.now()) - new Date(a.createdAt || Date.now())
      if (sortBy === 'oldest') return new Date(a.createdAt || Date.now()) - new Date(b.createdAt || Date.now())
      if (sortBy === 'price-low') return (Number(a.fare) || 0) - (Number(b.fare) || 0)
      if (sortBy === 'price-high') return (Number(b.fare) || 0) - (Number(a.fare) || 0)
      return 0
    })

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      <div className="panel">
        <div className="panel-header">
          <div className="panel-title-group">
            <span className="panel-eyebrow">Buses</span>
            <h2 className="panel-title">Bus List</h2>
            <p className="panel-desc">Total: {buses.length} | Showing: {filteredBuses.length}</p>
          </div>

          <div className="panel-actions">
            <button className="d-btn brand" type="button" onClick={openAddForm}>
              <Plus size={16} />
              Add Bus
            </button>
            <button className="d-btn ghost" type="button" onClick={getBuses}>
              <RefreshCw size={16} />
              Refresh
            </button>
          </div>
        </div>

        {/* Search & Sort */}
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '12px', marginTop: '16px' }}>
          <div style={{ position: 'relative', flex: 1, minWidth: '220px' }}>
            <Search size={15} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
            <input
              className="d-input"
              placeholder="Search by name, operator or number..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              style={{ paddingLeft: '36px' }}
            />
          </div>
          <select className="d-select" value={sortBy} onChange={(e) => setSortBy(e.target.value)} style={{ minWidth: '160px' }}>
            <option value="newest">Newest First</option>
            <option value="oldest">Oldest First</option>
            <option value="price-low">Price: Low to High</option>
            <option value="price-high">Price: High to Low</option>
          </select>
        </div>

        {message && <div className="d-message info" style={{ marginTop: '16px' }}>{message}</div>}
      </div>

      {filteredBuses.length === 0 ? (
        <div className="panel">
          <div className="empty-state">
            <Bus size={34} />
            <p className="empty-state-title">No buses found</p>
            <p className="empty-state-desc">{search ? 'Try changing your search.' : 'Click Add Bus to create your first bus.'}</p>
          </div>
        </div>
      ) : (
        <div className="card-grid">
          {filteredBuses.map((bus) => (
            <div className="item-card card-animated animate-fadeInUp" key={bus._id}>
              {bus.images?.[0] ? (
                <LazyImage className="item-card-img" src={bus.images[0]} alt={bus.busName} />
              ) : (
                <div className="item-card-img" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'var(--bg-input)' }}>
                  <Bus size={42} />
                </div>
              )}

              <div className="item-card-body">
                <h3 className="item-card-title">{bus.busName}</h3>
                <p className="item-card-sub">{bus.busNumber} | {bus.busType}</p>
                <p className="item-card-desc">{showPlace(bus.fromCityID)} to {showPlace(bus.toCityID)}</p>

                <div className="item-card-meta">
                  <IndianRupee size={15} />
                  {bus.fare}
                </div>

                <div className="item-card-meta">
                  Seats Left: {bus.availableSeats}
                </div>

                <div className="item-card-meta">
                  Booked Seats: {bus.totalSeats - bus.availableSeats}
                </div>

                <div className="item-card-actions">
                  <button className="d-btn ghost sm" type="button" onClick={() => openEditForm(bus)}>
                    <Edit3 size={14} />
                    Edit
                  </button>
                  <button className="d-btn danger sm" type="button" onClick={() => askDeleteConfirm(bus)}>
                    <Trash2 size={14} />
                    Delete
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      
        {isFormOpen && (
          <div className="modal-overlay"
          >
            <form className="modal-box wide" 
              onSubmit={saveBus}
            >
              <div className="modal-header">
                <div >
                  <p className="modal-eyebrow">Bus Form</p>
                  <h2 className="modal-title">{editId ? 'Update Bus' : 'Add Bus'}</h2>
                </div>
                <button className="modal-close"
