              <div className="d-form cols-2">
                <div className="span-2" style={{ fontWeight: 700, color: 'var(--text-heading)', marginTop: '4px' }}>
                  Bus Details
                </div>

                <div className="d-field">
                  <label className="d-label">Bus Name</label>
