                  <label className="d-label">From City</label>
                  <select className="d-select" name="fromCityID" value={formData.fromCityID} onChange={handleChange} required>
                    <option value="">Select From City</option>
                    {locations.map((location) => (
                      <option key={location._id} value={location._id}>
                        {location.city}, {location.state}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="d-field">
                  <label className="d-label">To City</label>
                  <select className="d-select" name="toCityID" value={formData.toCityID} onChange={handleChange} required>
                    <option value="">Select To City</option>
                    {locations.map((location) => (
                      <option key={location._id} value={location._id}>
                        {location.city}, {location.state}
                      </option>
                    ))}
                  </select>
                </div>



                <div className="d-field">
                  <label className="d-label">Duration</label>
                  <input className="d-input" name="duration" value={formData.duration} onChange={handleChange} placeholder="6 hours" />
                </div>

                <div className="span-2" style={{ fontWeight: 700, color: 'var(--text-heading)', marginTop: '8px' }}>
                  Seats And Price
                </div>

                <div className="d-field">
                  <label className="d-label">Total Seats</label>
                  <input className="d-input" type="number" name="totalSeats" value={formData.totalSeats} onChange={handleChange} required />
                </div>

                <div className="d-field">
                  <label className="d-label">Available Seats</label>
                  <input className="d-input" type="number" name="availableSeats" value={formData.availableSeats} onChange={handleChange} required />
                </div>

                <div className="d-field">
                  <label className="d-label">Fare</label>
                  <input className="d-input" type="number" name="fare" value={formData.fare} onChange={handleChange} required />
                </div>

                <div className="d-field">
                  <label className="d-label">Images</label>
                  <input className="d-file" type="file" multiple accept="image/*" onChange={(e) => setImages(e.target.files)} />
                </div>

                <div className="span-2" style={{ fontWeight: 700, color: 'var(--text-heading)', marginTop: '8px' }}>
                  Extra Details
                </div>

                <div className="d-field span-2">
                  <label className="d-label">Amenities</label>
                  <input className="d-input" value={amenities} onChange={(e) => setAmenities(e.target.value)} placeholder="Wifi, Water, Charging" />
                </div>

                <div className="d-field span-2">
                  <label className="d-label">Boarding Points</label>
                  <input className="d-input" value={boardingPoints} onChange={(e) => setBoardingPoints(e.target.value)} placeholder="Main Bus Stand, Railway Station" />
                </div>

                <div className="d-field span-2">
                  <label className="d-label">Dropping Points</label>
                  <input className="d-input" value={droppingPoints} onChange={(e) => setDroppingPoints(e.target.value)} placeholder="City Center, Airport Road" />
                </div>
              </div>

              <div className="modal-footer">
                <button className="d-btn ghost"
                  type="button"
                  onClick={() => {
                    setIsFormOpen(false)
                    resetForm()
                  }}
                >
                  <X size={16} />
                  Cancel
                </button>
                <button className="d-btn brand" disabled={loading}>
                  <Plus size={16} />
                  {loading ? 'Saving...' : editId ? 'Update Bus' : 'Add Bus'}
                </button>
              </div>
            </form>
          </div>
        )}
      

      {/* Confirm Alert */}
      {confirmAlert && (
        <ConfirmAlert
          message={confirmAlert.message}
          onConfirm={confirmAlert.onConfirm}
          onCancel={() => setConfirmAlert(null)}
        />
      )}
    </div>
  )
}

export default AddBus

import { Edit3, IndianRupee, Plus, RefreshCw, Search, Trash2, X } from 'lucide-react'
import { useEffect, useState } from 'react'
import ConfirmAlert from '../components/ConfirmAlert'
import LazyImage from '../components/LazyImage'
import axiosInstance from '../utils/axiosInstance'

const API_URL = '/location'

const Addlocation = () => {
  const [formData, setFormData] = useState({
    city: '',
    state: '',
    country: 'India',
    shortDescription: '',
    startingPrice: '',
  })
  const [image, setImage] = useState(null)
  const [locations, setLocations] = useState([])
  const [message, setMessage] = useState('')
  const [loading, setLoading] = useState(false)
  const [isFormOpen, setIsFormOpen] = useState(false)
  const [editId, setEditId] = useState('')

  // Search & Sort
  const [search, setSearch] = useState('')
  const [sortBy, setSortBy] = useState('newest')

  // Confirm Alert
  const [confirmAlert, setConfirmAlert] = useState(null)

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value })
  }

  const getLocations = async () => {
    try {
      const res = await axiosInstance.get(`${API_URL}/get`)
      setLocations(res.data.locations)
    } catch (error) {
      setMessage(error.response?.data?.message || 'Location load failed')
    }
  }

  const resetForm = () => {
    setFormData({
      city: '',
      state: '',
      country: 'India',
      shortDescription: '',
      startingPrice: '',
    })
    setImage(null)
    setEditId('')
  }

  const openAddForm = () => {
    resetForm()
    setMessage('')
    setIsFormOpen(true)
  }

  const openEditForm = (location) => {
    setFormData({
      city: location.city || '',
      state: location.state || '',
      country: location.country || 'India',
      shortDescription: location.shortDescription || '',
      startingPrice: location.startingPrice || '',
    })
    setImage(null)
    setEditId(location._id)
    setMessage('')
    setIsFormOpen(true)
  }

  const saveLocation = async (e) => {
    e.preventDefault()
    setMessage('')
    setLoading(true)

    try {
      const locationData = new FormData()

      Object.keys(formData).forEach((key) => {
        locationData.append(key, formData[key])
      })

      if (image) {
        locationData.append('image', image)
      }

      if (editId) {
        const res = await axiosInstance.put(`${API_URL}/update/${editId}`, locationData, {
          headers: { 'Content-Type': 'multipart/form-data' },
        })
        setMessage(res.data.message)
        setLocations((oldLocations) =>
          oldLocations.map((location) => (location._id === editId ? res.data.location : location))
        )
      } else {
        const res = await axiosInstance.post(`${API_URL}/add`, locationData, {
          headers: { 'Content-Type': 'multipart/form-data' },
        })
        setMessage(res.data.message)
        setLocations((oldLocations) => [res.data.location, ...oldLocations])
      }

      resetForm()
      setIsFormOpen(false)
    } catch (error) {
      setMessage(error.response?.data?.message || 'Location save failed')
    } finally {
      setLoading(false)
    }
  }

  const askDeleteConfirm = (location) => {
    setConfirmAlert({
      message: `Delete location "${location.city}"? This action cannot be undone.`,
      onConfirm: async () => {
        setConfirmAlert(null)
        try {
          const res = await axiosInstance.delete(`${API_URL}/delete/${location._id}`)
          setMessage(res.data.message)
          setLocations((old) => old.filter((l) => l._id !== location._id))
        } catch (error) {
          setMessage(error.response?.data?.message || 'Location delete failed')
        }
      }
    })
  }

  useEffect(() => {
    getLocations()
  }, [])

  const filteredLocations = locations
    .filter(loc => {
      const q = search.toLowerCase()
      if (!q) return true
      return (loc.city || '').toLowerCase().includes(q) || 
             (loc.state || '').toLowerCase().includes(q)
    })
    .sort((a, b) => {
      if (sortBy === 'newest') return new Date(b.createdAt) - new Date(a.createdAt)
      if (sortBy === 'oldest') return new Date(a.createdAt) - new Date(b.createdAt)
      if (sortBy === 'price-low') return (Number(a.startingPrice) || 0) - (Number(b.startingPrice) || 0)
      if (sortBy === 'price-high') return (Number(b.startingPrice) || 0) - (Number(a.startingPrice) || 0)
      return 0
    })

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      {/* Panel header */}
      <div className="panel">
        <div className="panel-header">
          <div className="panel-title-group">
            <span className="panel-eyebrow">Locations</span>
            <h2 className="panel-title">Location List</h2>
            <p className="panel-desc">Total: {locations.length} | Showing: {filteredLocations.length}</p>
          </div>
          <div className="panel-actions">
            <button className="d-btn brand" type="button" onClick={openAddForm}>
              <Plus size={16} />
              Add Location
            </button>
            <button className="d-btn ghost" type="button" onClick={getLocations}>
              <RefreshCw size={16} />
              Refresh
            </button>
          </div>
        </div>

        {/* Search & Sort */}
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '12px', marginTop: '16px' }}>
          <div style={{ position: 'relative', flex: 1, minWidth: '220px' }}>
            <Search size={15} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
            <input
              className="d-input"
              placeholder="Search by city or state..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              style={{ paddingLeft: '36px' }}
            />
          </div>
          <select className="d-select" value={sortBy} onChange={(e) => setSortBy(e.target.value)} style={{ minWidth: '160px' }}>
            <option value="newest">Newest First</option>
            <option value="oldest">Oldest First</option>
            <option value="price-low">Price: Low to High</option>
            <option value="price-high">Price: High to Low</option>
          </select>
        </div>

        {message && <div className="d-message info" style={{ marginTop: '16px' }}>{message}</div>}
      </div>

      {/* Location cards */}
      {filteredLocations.length === 0 ? (
        <div className="panel">
          <div className="empty-state">
            <div className="empty-state-icon">📍</div>
            <p className="empty-state-title">No locations yet</p>
            <p className="empty-state-desc">{search ? 'Try changing your search.' : 'Add your first travel location to get started.'}</p>
          </div>
        </div>
      ) : (
        <div className="card-grid">
          {filteredLocations.map((location) => (
            <div className="item-card card-animated animate-fadeInUp" key={location._id}>
              <LazyImage 
                className="item-card-img" 
                src={location.image} 
                alt={location.city} 
              />
              <div className="item-card-body">
                <h3 className="item-card-title">{location.city}, {location.state}</h3>
                <p className="item-card-sub">{location.country}</p>
                <p className="item-card-desc">{location.shortDescription}</p>
                <div className="item-card-meta">
                  <IndianRupee size={15} />
                  {location.startingPrice} starting
                </div>
                <div className="item-card-actions">
                  <button className="d-btn ghost sm" type="button" onClick={() => openEditForm(location)}>
                    <Edit3 size={14} />
                    Edit
                  </button>
                  <button className="d-btn danger sm" type="button" onClick={() => askDeleteConfirm(location)}>
                    <Trash2 size={14} />
                    Delete
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Add / Edit modal */}
      
        {isFormOpen && (
          <div className="modal-overlay"
          >
            <form className="modal-box" 
              onSubmit={saveLocation}
            >
              <div className="modal-header">
                <div >
                  <p className="modal-eyebrow">Locations</p>
                  <h2 className="modal-title">{editId ? 'Update Location' : 'Add Location'}</h2>
                </div>
                <button className="modal-close"
                  type="button"
                  onClick={() => { setIsFormOpen(false); resetForm() }}
                >
                  <X size={18} />
                </button>
              </div>

              <div className="d-form cols-2">
                <div className="d-field">
                  <label className="d-label">City</label>
                  <input className="d-input" name="city" value={formData.city} onChange={handleChange} placeholder="City" />
                </div>
                <div className="d-field">
                  <label className="d-label">State</label>
                  <input className="d-input" name="state" value={formData.state} onChange={handleChange} placeholder="State" />
                </div>
                <div className="d-field">
                  <label className="d-label">Country</label>
                  <input className="d-input" name="country" value={formData.country} onChange={handleChange} placeholder="Country" />
                </div>
                <div className="d-field">
                  <label className="d-label">Starting Price</label>
                  <div className="d-input-wrapper">
                    <span className="d-input-icon"><IndianRupee size={16} /></span>
                    <input
                      className="d-input with-icon"
                      type="number"
                      name="startingPrice"
                      value={formData.startingPrice}
                      onChange={handleChange}
                      placeholder="Starting price"
                    />
                  </div>
                </div>
                <div className="d-field">
                  <label className="d-label">Upload Image</label>
                  <input className="d-file" type="file" accept="image/*" onChange={(e) => setImage(e.target.files[0])} />
                </div>
                <div className="d-field span-2">
                  <label className="d-label">Short Description</label>
                  <textarea
                    className="d-textarea"
                    name="shortDescription"
                    value={formData.shortDescription}
                    onChange={handleChange}
                    placeholder="Small detail about this place"
                  />
                </div>
              </div>

              <div className="modal-footer">
                <button className="d-btn ghost"
                  type="button"
                  onClick={() => { setIsFormOpen(false); resetForm() }}
                >
                  <X size={16} />
                  Cancel
                </button>
                <button className="d-btn brand" disabled={loading}>
                  <Plus size={16} />
                  {loading ? 'Saving…' : editId ? 'Update Location' : 'Add Location'}
                </button>
              </div>

              {message && <div className="d-message info" style={{ marginTop: '16px' }}>{message}</div>}
            </form>
          </div>
        )}
      

      {/* Confirm Alert */}
      {confirmAlert && (
        <ConfirmAlert
          message={confirmAlert.message}
          onConfirm={confirmAlert.onConfirm}
          onCancel={() => setConfirmAlert(null)}
        />
      )}
    </div>
  )
}

export default Addlocation

import React, { useState, useEffect } from 'react'
import { Bus, CheckCircle, XCircle } from 'lucide-react'
import { useAuth } from '../customhooks/AuthContext'
import axiosInstance from '../utils/axiosInstance'

const GetOperator = () => {
  const [operators, setOperators] = useState([])
  const [message, setMessage] = useState('')
  const { token } = useAuth()

  const fetchOperators = async () => {
    try {
      const res = await axiosInstance.get('/operator/get')
      setOperators(res.data.operators || [])
    } catch (err) {
      console.error(err)
    }
  }

  useEffect(() => {
    fetchOperators()
  }, [])

  const handleApprove = async (id, isApproved) => {
    try {
      const endpoint = isApproved ? 'approveOperator' : 'rejectOperator'
      await axiosInstance.put(`/operator/${endpoint}/${id}`, {})
      setMessage(`Operator ${isApproved ? 'approved' : 'unapproved'} successfully`)
      fetchOperators()

      setTimeout(() => setMessage(''), 3000)
    } catch (error) {
      setMessage(error.response?.data?.message || 'Failed to update approval status')
    }
  }

  return (
    <div className="panel" style={{ padding: '24px' }}>
      <h2 style={{ fontSize: '20px', fontWeight: 'bold', marginBottom: '16px', display: 'flex', alignItems: 'center', gap: '8px' }}>
        <Bus size={24} /> Bus Operators Management
      </h2>

      {message && (
        <div style={{ padding: '12px', borderRadius: '8px', marginBottom: '20px', background: 'rgba(52,211,153,0.1)', color: '#34d399' }}>
          {message}
        </div>
      )}

      {operators.length > 0 ? (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
          {operators.map(op => (
            <div key={op._id} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '16px', border: '1px solid var(--border-subtle)', borderRadius: '12px', background: 'var(--bg-panel)' }}>
              <div>
                <h3 style={{ margin: '0 0 4px', fontSize: '16px', fontWeight: 'bold' }}>{op.agencyName}</h3>
                <p style={{ margin: 0, fontSize: '14px', color: 'var(--text-muted)' }}>Contact: {op.contactPerson} ({op.businessPhone})</p>
                <p style={{ margin: 0, fontSize: '14px', color: 'var(--text-muted)' }}>Email: {op.businessEmail}</p>
                <span style={{ display: 'inline-block', marginTop: '8px', padding: '4px 8px', borderRadius: '4px', fontSize: '12px', background: op.isApproved ? 'rgba(16,185,129,0.1)' : 'rgba(245,158,11,0.1)', color: op.isApproved ? '#10b981' : '#f59e0b' }}>
                  {op.isApproved ? 'Approved' : 'Pending Approval'}
                </span>
              </div>
              <div>
                {op.isApproved ? (
                  <button onClick={() => handleApprove(op._id, false)} className="btn-primary" style={{ background: '#ef4444', display: 'flex', alignItems: 'center', gap: '8px', border: 'none' }}>
                    <XCircle size={16} /> Revoke Access
                  </button>
                ) : (
                  <button onClick={() => handleApprove(op._id, true)} className="btn-primary" style={{ background: '#10b981', display: 'flex', alignItems: 'center', gap: '8px', border: 'none' }}>
                    <CheckCircle size={16} /> Approve
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>
      ) : (
        <p style={{ color: 'var(--text-muted)' }}>No operators registered yet.</p>
      )}
    </div>
  )
}

export default GetOperator

import { CheckCircle, Eye, IndianRupee, Mail, MapPin, RefreshCw, Search, Trash2, X, XCircle } from 'lucide-react'
import { useEffect, useState } from 'react'
import ConfirmAlert from '../components/ConfirmAlert'
import LazyImage from '../components/LazyImage'
import { useAuth } from '../customhooks/AuthContext'
import axiosInstance from '../utils/axiosInstance'

const API_URL = '/hotel'

const ManageHotel = () => {
  const [hotels, setHotels] = useState([])
  const [message, setMessage] = useState('')
  const [loading, setLoading] = useState(false)
  const [selectedHotel, setSelectedHotel] = useState(null)

  // Search & Sort
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('all')
  const [sortBy, setSortBy] = useState('newest')

  // Confirm alert
  const [confirmAlert, setConfirmAlert] = useState(null)
  // { message, onConfirm }

  const { token } = useAuth()

  const getHotels = async () => {
    setLoading(true)
    try {
      const res = await axiosInstance.get(`${API_URL}/gethotel`)
      setHotels(res.data.hotels)
    } catch (error) {
      setMessage(error.response?.data?.message || 'Hotel load failed')
    } finally {
      setLoading(false)
    }
  }

  const approveHotel = async (id) => {
    try {
      const res = await axiosInstance.put(`${API_URL}/approvehotel/${id}`, {}, {
        headers: { Authorization: `Bearer ${token}` },
      })
      setMessage(res.data.message)
      getHotels()
    } catch (error) {
      setMessage(error.response?.data?.message || 'Approve failed')
    }
  }

  const rejectHotel = async (id) => {
    try {
      const res = await axiosInstance.put(
        `${API_URL}/reject/${id}`,
        { message: 'Rejected by admin' },
        { headers: { Authorization: `Bearer ${token}` } },
      )
      setMessage(res.data.message)
      getHotels()
    } catch (error) {
      setMessage(error.response?.data?.message || 'Reject failed')
    }
  }

  const deleteHotel = async (id) => {
    try {
      const res = await axiosInstance.delete(`${API_URL}/deletehotel/${id}`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      setMessage(res.data.message)
      getHotels()
    } catch (error) {
      setMessage(error.response?.data?.message || 'Delete failed')
    }
  }

  const askDeleteConfirm = (hotel) => {
    setConfirmAlert({
      message: `Are you sure you want to delete "${hotel.hotelName}"? This action cannot be undone.`,
      onConfirm: () => {
        setConfirmAlert(null)
        deleteHotel(hotel._id)
      }
    })
  }

  const askRejectConfirm = (hotel) => {
    setConfirmAlert({
      message: `Reject "${hotel.hotelName}"? The hotel owner will be notified.`,
      onConfirm: () => {
        setConfirmAlert(null)
        rejectHotel(hotel._id)
      }
    })
  }

  useEffect(() => {
    getHotels()
  }, [])

  // Filter & Sort
  const filteredHotels = hotels
    .filter(hotel => {
      const q = search.toLowerCase()
      const matchSearch = !q ||
        (hotel.hotelName || '').toLowerCase().includes(q) ||
        (hotel.location?.city || '').toLowerCase().includes(q) ||
        (hotel.location?.state || '').toLowerCase().includes(q)

      const isApproved = hotel.approvalStatus?.status === true
      const isRejected = hotel.approvalStatus?.message === 'Rejected by admin' || hotel.approvalStatus?.message === 'Rejected'
      const matchStatus =
        statusFilter === 'all' ||
        (statusFilter === 'approved' && isApproved) ||
        (statusFilter === 'pending' && !isApproved && !isRejected) ||
        (statusFilter === 'rejected' && isRejected)

      return matchSearch && matchStatus
    })
    .sort((a, b) => {
      if (sortBy === 'newest') return new Date(b.createdAt) - new Date(a.createdAt)
      if (sortBy === 'oldest') return new Date(a.createdAt) - new Date(b.createdAt)
      if (sortBy === 'name') return a.hotelName.localeCompare(b.hotelName)
      if (sortBy === 'price-low') return a.pricePerNight - b.pricePerNight
      if (sortBy === 'price-high') return b.pricePerNight - a.pricePerNight
      return 0
    })

  const showValue = (value) => {
    if (value === true) return 'Yes'
    if (value === false) return 'No'
    return value || 'Not added'
  }

  const DetailRow = ({ label, value }) => (
    <div className="detail-row">
      <p className="detail-row-label">{label}</p>
      <p className="detail-row-value">{showValue(value)}</p>
    </div>
  )

  const containerVariants = {
    hidden: { opacity: 0 },
    show: {
      opacity: 1,
      transition: { staggerChildren: 0.1 }
    }
  }

  const itemVariants = {
    hidden: { opacity: 0, y: 15 },
    show: { opacity: 1, y: 0, transition: { type: 'spring', stiffness: 300, damping: 24 } }
  }

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      {/* Panel header */}
      <div className="panel">
        <div className="panel-header">
          <div className="panel-title-group">
            <span className="panel-eyebrow">Super Admin</span>
            <h2 className="panel-title">Manage Hotels</h2>
            <p className="panel-desc">Approve and remove hotel records. Total: {hotels.length} | Showing: {filteredHotels.length}</p>
          </div>
          <div className="panel-actions">
            <button className="d-btn ghost" onClick={getHotels}>
              <RefreshCw size={16} />
              Refresh
            </button>
          </div>
        </div>

        {/* Search & Filter */}
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '12px', marginTop: '16px' }}>
          <div style={{ position: 'relative', flex: 1, minWidth: '220px' }}>
            <Search size={15} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
            <input
              className="d-input"
              placeholder="Search by name, city, state..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              style={{ paddingLeft: '36px' }}
            />
          </div>
          <select className="d-select" value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)} style={{ minWidth: '140px' }}>
            <option value="all">All Status</option>
            <option value="approved">Approved</option>
            <option value="pending">Pending</option>
            <option value="rejected">Rejected</option>
          </select>
          <select className="d-select" value={sortBy} onChange={(e) => setSortBy(e.target.value)} style={{ minWidth: '160px' }}>
            <option value="newest">Newest First</option>
            <option value="oldest">Oldest First</option>
            <option value="name">Name A-Z</option>
            <option value="price-low">Price: Low to High</option>
            <option value="price-high">Price: High to Low</option>
          </select>
        </div>

        {message && <div className="d-message info" style={{ marginTop: '12px' }}>{message}</div>}
      </div>

      {/* Hotel cards */}
      {loading ? (
        <div className="card-grid">
          <div>Loading...</div>
        </div>
      ) : filteredHotels.length === 0 ? (
        <div className="panel">
          <div className="empty-state">
            <div className="empty-state-icon">🏨</div>
            <p className="empty-state-title">No hotels found</p>
            <p className="empty-state-desc">Try changing your search or filter.</p>
          </div>
        </div>
      ) : (
        <div className="card-grid" initial="hidden" animate="show">
          {filteredHotels.map((hotel) => {
            const isApproved = hotel.approvalStatus?.status === true
            const isRejected =
              hotel.approvalStatus?.message === 'Rejected by admin' ||
              hotel.approvalStatus?.message === 'Rejected'

            return (
              <div className="item-card card-animated" key={hotel._id}>
                <LazyImage
                  className="item-card-img"
                  src={hotel.images?.[0] || 'https://images.unsplash.com/photo-1566073771259-6a8506099945?auto=format&fit=crop&w=900&q=80'}
                  alt={hotel.hotelName}
                />

                <div className="item-card-body">
                  <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', gap: '8px', marginBottom: '4px' }}>
                    <h3 className="item-card-title" style={{ margin: 0 }}>{hotel.hotelName}</h3>
                    <span className={`status-badge ${isApproved ? 'approved' : isRejected ? 'rejected' : 'pending'}`}>
                      {isApproved ? 'Approved' : isRejected ? 'Rejected' : 'Pending'}
                    </span>
                  </div>
                  <p className="item-card-sub" style={{ textTransform: 'capitalize' }}>{hotel.hotelType}</p>

                  <p className="item-card-desc">{hotel.description}</p>

                  <div className="item-card-meta" style={{ marginBottom: '6px' }}>
                    <MapPin size={14} />
                    {hotel.location?.city || 'City'}, {hotel.location?.state || 'State'}
                  </div>
                  <div className="item-card-meta" style={{ marginBottom: '6px' }}>
                    <Mail size={14} />
                    <span style={{ wordBreak: 'break-all', fontSize: '13px' }}>{hotel.email || 'No email'}</span>
                  </div>
                  <div className="item-card-meta">
                    <IndianRupee size={14} />
                    {hotel.pricePerNight} / night
                  </div>

                  {hotel.amenities?.length > 0 && (
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px', margin: '10px 0' }}>
                      {hotel.amenities.slice(0, 4).map((item) => (
                        <span className="amenity-pill" key={item}>{item}</span>
                      ))}
                    </div>
                  )}

                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginTop: '12px' }}>
                    <button className="d-btn ghost sm" onClick={() => setSelectedHotel(hotel)}>
                      <Eye size={14} />
                      View
                    </button>
                    {!isApproved && (
                      <button className="d-btn success sm" onClick={() => approveHotel(hotel._id)}>
                        <CheckCircle size={14} />
                        Approve
                      </button>
                    )}
                    {!isRejected && (
                      <button className="d-btn warning sm" onClick={() => askRejectConfirm(hotel)}>
                        <XCircle size={14} />
                        Reject
                      </button>
                    )}
                    <button className="d-btn danger sm" onClick={() => askDeleteConfirm(hotel)}>
                      <Trash2 size={14} />
                      Delete
                    </button>
                  </div>
                </div>
              </div>
            )
          })}
        </div>
      )}

      {/* Hotel detail modal */}
      
        {selectedHotel && (
          <div 
            className="modal-overlay"
          >
            <div 
              className="modal-box wide"
            >
              <div className="modal-header">
              <div>
                <p className="modal-eyebrow">Hotel Details</p>
                <h2 className="modal-title">{selectedHotel.hotelName}</h2>
                <p style={{ fontSize: '13px', color: 'var(--text-muted)', textTransform: 'capitalize' }}>{selectedHotel.hotelType}</p>
              </div>
              <button className="modal-close" type="button" onClick={() => setSelectedHotel(null)}>
                <X size={18} />
              </button>
            </div>

            {/* Images */}
            <div className="img-gallery">
              {selectedHotel.images?.length > 0 ? (
                selectedHotel.images.map((image, index) => (
                  <LazyImage key={image} src={image} alt={`${selectedHotel.hotelName} ${index + 1}`} />
                ))
              ) : (
                <LazyImage
                  src="https://images.unsplash.com/photo-1566073771259-6a8506099945?auto=format&fit=crop&w=900&q=80"
                  alt={selectedHotel.hotelName}
                />
              )}
            </div>

            <div className="detail-grid">
              <DetailRow label="Hotel Name" value={selectedHotel.hotelName} />
              <DetailRow label="Hotel Type" value={selectedHotel.hotelType} />
              <DetailRow label="Email" value={selectedHotel.email} />
              <DetailRow label="Contact Number" value={selectedHotel.contactNumber} />
              <DetailRow label="Price Per Night" value={`Rs. ${selectedHotel.pricePerNight || 0}`} />
              <DetailRow label="Total Rooms" value={selectedHotel.totalRooms} />
              <DetailRow label="Available Rooms" value={selectedHotel.availableRooms} />
              <DetailRow label="Check In Time" value={selectedHotel.checkInTime} />
              <DetailRow label="Check Out Time" value={selectedHotel.checkOutTime} />
              <DetailRow label="Address" value={selectedHotel.location?.address} />
              <DetailRow label="City" value={selectedHotel.location?.city} />
              <DetailRow label="State" value={selectedHotel.location?.state} />
              <DetailRow label="Country" value={selectedHotel.location?.country} />
              <DetailRow label="Pincode" value={selectedHotel.location?.pincode} />
              <DetailRow label="Rating" value={selectedHotel.rating} />
              <DetailRow label="Reviews Count" value={selectedHotel.reviewsCount} />
              <DetailRow label="Featured" value={selectedHotel.isFeatured} />
              <DetailRow label="Active" value={selectedHotel.isActive} />
              <DetailRow label="Approval Status" value={selectedHotel.approvalStatus?.status ? 'Approved' : selectedHotel.approvalStatus?.message || 'Pending'} />
              <DetailRow label="Created At" value={selectedHotel.createdAt ? new Date(selectedHotel.createdAt).toLocaleString() : ''} />
            </div>

            <div className="detail-row" style={{ marginTop: '12px' }}>
              <p className="detail-row-label">Amenities</p>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px', marginTop: '8px' }}>
                {selectedHotel.amenities?.length > 0 ? (
                  selectedHotel.amenities.map((item) => (
                    <span className="amenity-pill" key={item}>{item}</span>
                  ))
                ) : (
                  <span style={{ fontSize: '14px', color: 'var(--text-muted)' }}>Not added</span>
                )}
              </div>
            </div>

            <div className="detail-row" style={{ marginTop: '12px' }}>
              <p className="detail-row-label">Description</p>
              <p className="detail-row-value" style={{ whiteSpace: 'pre-wrap', marginTop: '4px' }}>{showValue(selectedHotel.description)}</p>
            </div>

            <div className="modal-footer">
              <button className="d-btn ghost" type="button" onClick={() => setSelectedHotel(null)}>
                Close
              </button>
            </div>
            </div>
          </div>
        )}
      

      {/* Confirm Alert */}
      {confirmAlert && (
        <ConfirmAlert
          message={confirmAlert.message}
          onConfirm={confirmAlert.onConfirm}
          onCancel={() => setConfirmAlert(null)}
        />
      )}
    </div>
  )
}

export default ManageHotel

import axios from 'axios'
import { Edit3, KeyRound, Mail, Phone, RotateCcw, Save, ShieldCheck, UserRound, X } from 'lucide-react'
import { useEffect, useState } from 'react'
import { useAuth } from '../customhooks/AuthContext'
import LazyImage from '../components/LazyImage'
import axiosInstance from '../utils/axiosInstance'

const API_URL = '/user'

const SuperAProfile = () => {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    gender: '',
    profileImage: '',
  })
  const [savedProfile, setSavedProfile] = useState(null)
  const [profileImageFile, setProfileImageFile] = useState(null)
  const [profileImagePreview, setProfileImagePreview] = useState('')
  const [isEditing, setIsEditing] = useState(false)
  const [passwordData, setPasswordData] = useState({
    oldPassword: '',
    newPassword: '',
  })
  const [isPasswordModalOpen, setIsPasswordModalOpen] = useState(false)
  const [message, setMessage] = useState('')
  const [passwordMessage, setPasswordMessage] = useState('')
  const [loading, setLoading] = useState(false)

  const { user: savedUser, token, updateUser } = useAuth()
  const userName = `${formData.firstName || 'Super'} ${formData.lastName || 'Admin'}`
  const avatarText = `${formData.firstName?.[0] || 'S'}${formData.lastName?.[0] || 'A'}`
  const displayImage = profileImagePreview || formData.profileImage

  const getProfile = async () => {
    try {
      const res = await axiosInstance.get(`${API_URL}/profile`)
      const profile = {
        firstName: res.data.user.firstName || '',
        lastName: res.data.user.lastName || '',
        email: res.data.user.email || '',
        phone: res.data.user.phone || '',
        gender: res.data.user.gender || '',
        profileImage: res.data.user.profileImage || '',
      }
      setFormData(profile)
      setSavedProfile(profile)
      setProfileImageFile(null)
      setProfileImagePreview('')
    } catch (error) {
      setMessage(error.response?.data?.message || 'Profile load failed')
    }
  }

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value })
  }

  const handleProfileImageChange = (e) => {
    const file = e.target.files[0]
    if (!file) return
    setProfileImageFile(file)
    setProfileImagePreview(URL.createObjectURL(file))
  }

  const resetProfileForm = () => {
    if (savedProfile) setFormData(savedProfile)
    setProfileImageFile(null)
    setProfileImagePreview('')
    setMessage('')
  }

  const cancelEdit = () => {
    resetProfileForm()
    setIsEditing(false)
  }

  const updateProfile = async (e) => {
    e.preventDefault()
    setMessage('')
    setLoading(true)

    try {
      const profileData = new FormData()
      Object.keys(formData).forEach((key) => {
        if (key !== 'profileImage') profileData.append(key, formData[key])
      })
      if (profileImageFile) profileData.append('profileImage', profileImageFile)

      const res = await axiosInstance.put(`${API_URL}/updateprofile`, profileData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      })

      updateUser(res.data.user)
      const updated = {
        firstName: res.data.user.firstName || '',
        lastName: res.data.user.lastName || '',
        email: res.data.user.email || '',
        phone: res.data.user.phone || '',
        gender: res.data.user.gender || '',
        profileImage: res.data.user.profileImage || '',
      }
      setFormData(updated)
      setSavedProfile(updated)
      setProfileImageFile(null)
      setProfileImagePreview('')
      setIsEditing(false)
      setMessage(res.data.message)
    } catch (error) {
      setMessage(error.response?.data?.message || 'Profile update failed')
    } finally {
      setLoading(false)
    }
  }

  const changePassword = async (e) => {
    e.preventDefault()
    setPasswordMessage('')

    try {
      const res = await axiosInstance.put(`${API_URL}/changepassword`, passwordData)
      setPasswordMessage(res.data.message)
      setPasswordData({ oldPassword: '', newPassword: '' })
      setIsPasswordModalOpen(false)
    } catch (error) {
      setPasswordMessage(error.response?.data?.message || 'Password change failed')
    }
  }

  useEffect(() => {
    getProfile()
  }, [])

  return (
    <div className="profile-layout">
      {/* ── Sidebar ── */}
      <div className="profile-sidebar">
        <div className="profile-avatar-wrap">
          {displayImage ? (
            <LazyImage className="profile-avatar" src={displayImage} alt={userName} />
          ) : (
            <div className="profile-avatar-initials">{avatarText}</div>
          )}
        </div>

        <h2 className="profile-name">{userName}</h2>
        <span className="profile-role">
          <ShieldCheck size={14} />
          Super Admin
        </span>

        <div className="profile-sidebar-actions">
          <button className="d-btn brand" type="button" onClick={() => setIsEditing(true)}>
            <Edit3 size={15} />
            Edit Profile
          </button>
          <button className="d-btn ghost" type="button" onClick={() => { setPasswordMessage(''); setIsPasswordModalOpen(true) }}>
            <KeyRound size={15} />
            Reset Password
          </button>
        </div>

        <div className="profile-meta-list">
          <div className="profile-meta-item">
            <Mail size={15} />
            <span>{formData.email || 'No email'}</span>
          </div>
          <div className="profile-meta-item">
            <Phone size={15} />
            <span>{formData.phone || 'No phone'}</span>
          </div>
        </div>
      </div>

      {/* ── Right panel ── */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
        <form className="panel" onSubmit={updateProfile}>
          <div className="panel-header">
            <div className="panel-title-group">
              <span className="panel-eyebrow">Account</span>
              <h2 className="panel-title">{isEditing ? 'Edit Profile' : 'Profile Details'}</h2>
            </div>
            {isEditing && (
              <div className="panel-actions">
                <button className="d-btn ghost" type="button" onClick={resetProfileForm}>
                  <RotateCcw size={15} />
                  Reset
                </button>
                <button className="d-btn ghost" type="button" onClick={cancelEdit}>
                  <X size={15} />
                  Cancel
                </button>
              </div>
            )}
          </div>

          <div className="d-form cols-2">
            <div className="d-field">
              <label className="d-label">First Name</label>
              <div className="d-input-wrapper">
                <span className="d-input-icon"><UserRound size={16} /></span>
                <input
                  className="d-input with-icon"
                  name="firstName"
                  value={formData.firstName}
                  onChange={handleChange}
                  disabled={!isEditing}
                />
              </div>
            </div>

            <div className="d-field">
              <label className="d-label">Last Name</label>
              <input className="d-input" name="lastName" value={formData.lastName} onChange={handleChange} disabled={!isEditing} />
            </div>

            <div className="d-field">
              <label className="d-label">Email</label>
              <input className="d-input" name="email" value={formData.email} onChange={handleChange} disabled={!isEditing} />
            </div>

            <div className="d-field">
              <label className="d-label">Phone</label>
              <input className="d-input" name="phone" value={formData.phone} onChange={handleChange} disabled={!isEditing} />
            </div>

            <div className="d-field">
              <label className="d-label">Gender</label>
              <select className="d-select" name="gender" value={formData.gender} onChange={handleChange} disabled={!isEditing}>
                <option value="">Select Gender</option>
                <option value="Male">Male</option>
                <option value="Female">Female</option>
                <option value="Other">Other</option>
              </select>
            </div>

            {isEditing && (
              <div className="d-field">
                <label className="d-label">Upload Profile Image</label>
                <input className="d-file" type="file" accept="image/*" onChange={handleProfileImageChange} />
              </div>
            )}
          </div>

          {isEditing && (
            <button className="d-btn brand" style={{ marginTop: '20px' }} disabled={loading}>
              <Save size={16} />
              {loading ? 'Saving…' : 'Save Profile'}
            </button>
          )}

          {message && <div className="d-message info" style={{ marginTop: '16px' }}>{message}</div>}
        </form>

        {passwordMessage && <div className="d-message info">{passwordMessage}</div>}
      </div>

      {/* ── Change password modal ── */}
      {isPasswordModalOpen && (
        <div className="modal-overlay">
          <form className="modal-box" onSubmit={changePassword}>
            <div className="modal-header">
              <div>
                <p className="modal-eyebrow">Security</p>
                <h2 className="modal-title">Reset Password</h2>
              </div>
              <button
                className="modal-close"
                type="button"
                onClick={() => { setIsPasswordModalOpen(false); setPasswordData({ oldPassword: '', newPassword: '' }) }}
              >
                <X size={18} />
              </button>
            </div>

            <div className="d-form">
              <div className="d-field">
                <label className="d-label">Old Password</label>
                <input
                  className="d-input"
                  type="password"
                  value={passwordData.oldPassword}
                  onChange={(e) => setPasswordData({ ...passwordData, oldPassword: e.target.value })}
                />
              </div>
              <div className="d-field">
                <label className="d-label">New Password</label>
                <input
                  className="d-input"
                  type="password"
                  value={passwordData.newPassword}
                  onChange={(e) => setPasswordData({ ...passwordData, newPassword: e.target.value })}
                />
              </div>
            </div>

            <div className="modal-footer">
              <button
                className="d-btn ghost"
                type="button"
                onClick={() => { setIsPasswordModalOpen(false); setPasswordData({ oldPassword: '', newPassword: '' }) }}
              >
                <X size={16} />
                Cancel
              </button>
              <button className="d-btn brand">
                <KeyRound size={16} />
                Update Password
              </button>
            </div>

            {passwordMessage && <div className="d-message info" style={{ marginTop: '16px' }}>{passwordMessage}</div>}
          </form>
        </div>
      )}
    </div>
  )
}

export default SuperAProfile

